              </form>
           </div>

           {/* Footer Branding */}
           <div className="bg-white/[0.01] p-5 text-center border-t border-white/[0.05]">
              <p className="text-[8px] text-slate-700 uppercase tracking-[0.3em] font-bold">
                 Enterprise Terminal v4.2
              </p>
           </div>
        </div>
      </div>

    </div>
  );
};

export default Login;

