           <p className="text-slate-500 font-medium text-lg leading-snug">{item.name}</p>
        </div>
      </div>

      {/* CORE STATS GRID */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
         {/* PRICE CARD */}
         <div 
            onClick={() => setPriceVisible(!priceVisible)}
            className="bg-white p-6 rounded-3xl border border-slate-200 shadow-soft flex flex-col justify-between cursor-pointer group hover:border-brand-300 transition-all relative overflow-hidden"
          >
            <div className="absolute top-0 right-0 w-24 h-24 bg-slate-50/50 rounded-full -mr-12 -mt-12 group-hover:scale-110 transition-transform"></div>
            <div className="flex items-center justify-between text-slate-400 mb-4 relative z-10">
               <div className="flex items-center gap-2">
                 <Tag size={16} />
                 <span className="text-[10px] font-bold uppercase tracking-widest">Market Price (MRP)</span>
               </div>
               {priceVisible ? <EyeOff size={14} /> : <Eye size={14} className="text-brand-500" />}
            </div>
            <div className="flex items-baseline gap-1 relative z-10">
              <span className={`text-3xl font-black text-slate-900 transition-all duration-300 ${priceVisible ? 'blur-0' : 'blur-md select-none opacity-20'}`}>
                ₹{item.price.toLocaleString()}
              </span>
              {!priceVisible && <span className="text-[10px] font-bold text-brand-600 animate-pulse ml-2 uppercase">Reveal</span>}
            </div>
         </div>

         {/* STOCK CARD */}
         <div className={`p-6 rounded-3xl border shadow-soft flex flex-col justify-between overflow-hidden relative ${
            isZeroStock ? 'bg-rose-50 border-rose-100' : isLowStock ? 'bg-amber-50 border-amber-100' : 'bg-white border-slate-200'
         }`}>
            <div className="absolute top-0 right-0 w-24 h-24 bg-black/5 rounded-full -mr-12 -mt-12"></div>
            <div className={`flex items-center gap-2 mb-4 relative z-10 ${
                isZeroStock ? 'text-rose-600' : isLowStock ? 'text-amber-600' : 'text-slate-400'
            }`}>
               <Box size={16} />
               <span className="text-[10px] font-bold uppercase tracking-widest">On-Hand Inventory</span>
            </div>
            <div className={`text-3xl font-black relative z-10 tracking-tight ${
                isZeroStock ? 'text-rose-900' : isLowStock ? 'text-amber-900' : 'text-slate-900'
            }`}>
                {item.quantity} <span className="text-sm font-bold opacity-60 uppercase ml-1">PCS</span>
            </div>
         </div>

         {/* VALUATION CARD (Asset Value) */}
         <div className="bg-slate-900 p-6 rounded-3xl shadow-elevated flex flex-col justify-between sm:col-span-2 lg:col-span-1 overflow-hidden relative group">
            <div className="absolute -bottom-8 -right-8 w-32 h-32 bg-white/5 rounded-full blur-2xl group-hover:scale-125 transition-transform duration-700"></div>
            <div className="flex items-center gap-2 mb-4 text-slate-500 relative z-10">
               <IndianRupee size={16} />
               <span className="text-[10px] font-bold uppercase tracking-widest">Inventory Asset Value</span>
            </div>
            <div className="text-3xl font-black text-white relative z-10 tracking-tighter">
                ₹{stockValue.toLocaleString()}
            </div>
         </div>
      </div>

      {/* METADATA BAR */}
      <div className="bg-white rounded-2xl p-4 md:px-8 border border-slate-200 shadow-soft flex flex-wrap gap-6 md:gap-12 items-center">
          <div className="flex items-center gap-3">
             <div className="p-2 bg-slate-50 text-slate-400 rounded-lg"><Hash size={14}/></div>
             <div>
                <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest leading-none mb-1">HSN Code</p>
                <p className="font-bold text-slate-800 text-xs">{item.hsnCode}</p>
             </div>
          </div>
          <div className="flex items-center gap-3">
             <div className="p-2 bg-slate-50 text-slate-400 rounded-lg"><Clock size={14}/></div>
             <div>
                <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest leading-none mb-1">Last Update</p>
                <p className="font-bold text-slate-800 text-xs">{new Date(item.lastUpdated).toLocaleDateString(undefined, { day: '2-digit', month: 'short', year: 'numeric' })}</p>
             </div>
          </div>
          <div className="ml-auto hidden md:flex items-center gap-2 bg-teal-50 px-3 py-1.5 rounded-xl border border-teal-100">
             <div className="w-1.5 h-1.5 rounded-full bg-teal-500 animate-pulse"></div>
             <span className="text-[10px] font-bold text-teal-700 uppercase tracking-widest">Active SKU</span>
          </div>
      </div>

      {/* DETAILED HISTORY TABS */}
      <div className="bg-white rounded-[2rem] shadow-soft border border-slate-200 overflow-hidden flex flex-col min-h-[400px]">
          <div className="p-1 bg-slate-50 flex border-b border-slate-100">
              <button 
                onClick={() => setActiveTab('MOVEMENTS')}
                className={`flex-1 py-4 text-[10px] font-bold uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'MOVEMENTS' ? 'bg-white text-slate-900 shadow-sm rounded-t-2xl ring-1 ring-slate-100' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <Activity size={14} /> Movement Ledger
              </button>
              <button 
                onClick={() => setActiveTab('PRICING')}
                className={`flex-1 py-4 text-[10px] font-bold uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'PRICING' ? 'bg-white text-slate-900 shadow-sm rounded-t-2xl ring-1 ring-slate-100' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <History size={14} /> SKU Price Audit
              </button>
          </div>

          <div className="flex-1 overflow-auto no-scrollbar">
              {activeTab === 'MOVEMENTS' ? (
                <div className="divide-y divide-slate-50 animate-fade-in">
                   {transactions.length === 0 ? (
                      <div className="py-24 text-center text-slate-400">
                         <ArrowRightLeft size={48} className="mx-auto mb-4 opacity-10" />
                         <p className="text-[10px] font-bold uppercase tracking-widest">No transactions logged</p>
                      </div>
                   ) : (
                      transactions.map(tx => (
                        <div key={tx.id} className="p-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4 hover:bg-slate-50/50 transition-colors group">
                           <div className="flex items-center gap-4">
                              <div className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-sm ${
                                tx.type === TransactionType.SALE ? 'bg-teal-50 text-teal-600' : 
                                tx.type === TransactionType.PURCHASE ? 'bg-blue-50 text-blue-600' : 
                                'bg-rose-50 text-rose-600'
                              }`}>
                                 {tx.type === TransactionType.SALE ? <TrendingUp size={18}/> : 
                                  tx.type === TransactionType.PURCHASE ? <Package size={18}/> : <TrendingDown size={18}/>}
                              </div>
                              <div>
                                 <div className="flex items-center gap-2 mb-0.5">
                                    <span className="text-sm font-bold text-slate-900">{tx.type}</span>
                                    <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">• {new Date(tx.createdAt).toLocaleDateString()}</span>
                                 </div>
                                 <p className="text-xs text-slate-500 font-medium">{tx.customerName || 'Standard Entry'}</p>
                              </div>
                           </div>
                           <div className="flex items-center gap-8 text-right self-end sm:self-center">
                              <div className="space-y-0.5">
                                 <p className="text-[8px] font-bold text-slate-300 uppercase tracking-widest">Net Rate</p>
                                 <p className="font-bold text-slate-800 text-sm">₹{tx.price.toLocaleString()}</p>
                              </div>
                              <div className="min-w-[60px]">
                                 <span className={`text-lg font-black tracking-tight ${
                                   tx.type === TransactionType.SALE ? 'text-teal-600' : 
                                   tx.type === TransactionType.PURCHASE ? 'text-blue-600' : 
                                   'text-rose-600'
                                 }`}>
                                    {tx.type === TransactionType.SALE ? '-' : '+'}{tx.quantity}
                                 </span>
                              </div>
                           </div>
                        </div>
                      ))
                   )}
                </div>
              ) : (
                <div className="divide-y divide-slate-50 animate-fade-in">
                   {priceHistory.length === 0 ? (
                      <div className="py-24 text-center text-slate-400">
                         <History size={48} className="mx-auto mb-4 opacity-10" />
                         <p className="text-[10px] font-bold uppercase tracking-widest">No price changes detected</p>
                      </div>
                   ) : (
                      priceHistory.map(entry => {
                         const diff = entry.newPrice - entry.oldPrice;
                         const isIncrease = diff > 0;
                         return (
                            <div key={entry.id} className="p-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4 hover:bg-slate-50/50 transition-colors">
                               <div className="flex items-center gap-4">
                                  <div className="p-2.5 bg-slate-50 text-slate-400 rounded-xl">
                                     <Calendar size={18} />
                                  </div>
                                  <div>
                                     <p className="text-sm font-bold text-slate-900">{new Date(entry.changeDate).toLocaleDateString(undefined, { day: '2-digit', month: 'long', year: 'numeric' })}</p>
                                     <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">{new Date(entry.changeDate).toLocaleTimeString()}</p>
                                  </div>
                               </div>
                               <div className="flex items-center gap-10">
                                  <div className="text-right">
                                     <p className="text-[8px] font-bold text-slate-300 uppercase tracking-widest mb-1">Was</p>
                                     <p className="text-slate-400 font-bold text-sm line-through">₹{entry.oldPrice.toLocaleString()}</p>
                                  </div>
                                  <div className="text-center">
                                     <div className={`px-2 py-1 rounded-lg text-[9px] font-black flex items-center gap-1 shadow-inner ${isIncrease ? 'bg-rose-50 text-rose-600' : 'bg-teal-50 text-teal-600'}`}>
                                        {isIncrease ? <TrendingUp size={10}/> : <TrendingDown size={10}/>}
                                        {isIncrease ? '+' : ''}{diff.toLocaleString()}
                                     </div>
                                  </div>
                                  <div className="text-right">
                                     <p className="text-[8px] font-bold text-brand-400 uppercase tracking-widest mb-1">New MRP</p>
                                     <p className="text-slate-900 font-black text-xl tracking-tight">₹{entry.newPrice.toLocaleString()}</p>
                                  </div>
                               </div>
                            </div>
                         );
                      })
                   )}
                </div>
              )}
          </div>
      </div>

    </div>
  );
};

export default ItemDetail;

import React, { useEffect, useState, useRef } from 'react';
import { Role, TransactionType, User, StockItem, Customer, Brand } from '../types';
import { createBulkTransactions } from '../services/transactionService';
import { fetchInventory } from '../services/inventoryService';
import { getCustomers } from '../services/masterService';
import { 
  Search,
  Loader2,
  Trash2,
  Minus,
  Plus,
  ShoppingCart,
  User as UserIcon,
  PackagePlus,
  ArrowLeft,
  X,
  AlertCircle,
  Zap,
  ArrowRight,
  ChevronRight,
  Filter,
  ChevronDown,
  ChevronUp,
  LayoutGrid,
  CreditCard,
  Percent
} from 'lucide-react';

interface Props {
  user: User;
  forcedMode?: 'SALES' | 'PURCHASE' | 'RETURN';
  onSearchToggle?: (isOpen: boolean) => void;
}

interface CartItem {
  tempId: string;
  partNumber: string;
  name?: string; 
  type: TransactionType;
  quantity: number;
  price: number; // This is the Net Price (MRP - Discount) saved to DB
  mrp: number;   // Original MRP for calculation
  discount: number; // Percentage
  customerName: string;
  stockError?: boolean;
}

const DailyTransactions: React.FC<Props> = ({ user, forcedMode, onSearchToggle }) => {
  const [mode, setMode] = useState<'SALES' | 'PURCHASE' | 'RETURN'>(forcedMode || 'SALES');
  const [inventory, setInventory] = useState<StockItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [search, setSearch] = useState('');
  const [suggestions, setSuggestions] = useState<StockItem[]>([]);
  const [customerName, setCustomerName] = useState('');
  const [savedCustomers, setSavedCustomers] = useState<Customer[]>([]);
  const [customerSuggestions, setCustomerSuggestions] = useState<Customer[]>([]);
  const [showCustomerList, setShowCustomerList] = useState(false);
  const [selectedBrand, setSelectedBrand] = useState<Brand | 'ALL'>('ALL');
  const wrapperRef = useRef<HTMLDivElement>(null);
  const [showMobileSearch, setShowMobileSearch] = useState(false);

  const [hideFilters, setHideFilters] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchInventory().then(setInventory);
    if (mode === 'SALES') {
      getCustomers().then(data => Array.isArray(data) && setSavedCustomers(data));
    }
    const handleClickOutside = (e: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(e.target as Node)) setShowCustomerList(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [mode]);

  useEffect(() => { if (forcedMode) setMode(forcedMode); }, [forcedMode]);

  useEffect(() => {
    if (onSearchToggle) onSearchToggle(showMobileSearch);
  }, [showMobileSearch, onSearchToggle]);

  const handleSearch = (val: string) => {
    setSearch(val);
    if (val.length > 0) {
       if (val.length > 1) setHideFilters(true);

       let filtered = inventory.filter(i => 
         i.partNumber.toLowerCase().includes(val.toLowerCase()) || 
         i.name.toLowerCase().includes(val.toLowerCase())
       );
       if (selectedBrand !== 'ALL') {
         filtered = filtered.filter(i => i.brand === selectedBrand);
       }
       setSuggestions(filtered.slice(0, 30));
    } else {
       setSuggestions([]);
       setHideFilters(false);
    }
  };

  const handleCustomerType = (val: string) => {
    setCustomerName(val);
    if (mode === 'SALES' && val.length > 0) {
      const lowerVal = val.toLowerCase();
      setCustomerSuggestions(savedCustomers.filter(c => 
        (c.name?.toLowerCase().includes(lowerVal)) || (c.phone?.includes(val))
      ).slice(0, 5));
      setShowCustomerList(true);
    } else setShowCustomerList(false);
  };

  const addToCart = (item: StockItem) => {
      const existing = cart.find(c => c.partNumber === item.partNumber);
      if (existing) {
          updateQty(existing.tempId, 1);
          resetSearch();
          return;
      }
      if (mode === 'SALES' && item.quantity === 0) return alert("Item out of stock!");

      // Standard Purchase Discount is 12% by default as per shop rule
      const initialDiscount = mode === 'PURCHASE' ? 12 : 0;
      const initialPrice = mode === 'PURCHASE' 
        ? item.price * (1 - initialDiscount / 100) 
        : item.price;

      const newItem: CartItem = {
          tempId: Math.random().toString(36),
          partNumber: item.partNumber,
          name: item.name, 
          type: mode === 'SALES' ? TransactionType.SALE : mode === 'PURCHASE' ? TransactionType.PURCHASE : TransactionType.RETURN,
          quantity: 1,
          mrp: item.price,
          discount: initialDiscount,
          price: initialPrice,
          customerName: customerName,
          stockError: false
      };
      setCart(prev => [...prev, newItem]);
      resetSearch();
  };

  const resetSearch = () => {
    setSearch('');
    setSuggestions([]);
    setShowMobileSearch(false);
    setHideFilters(false);
  };

  const updateQty = (id: string, delta: number) => {
      setCart(prev => prev.map(item => {
          if (item.tempId === id) {
              let newQty = item.quantity + delta;
              if (newQty < 1) newQty = 1;
              if (mode === 'SALES') {
                  const stockItem = inventory.find(i => i.partNumber === item.partNumber);
                  if (stockItem && newQty > stockItem.quantity) newQty = stockItem.quantity;
              }
              return { ...item, quantity: newQty };
          }
          return item;
      }));
  };

  const handleDiscountChange = (id: string, val: string) => {
    const disc = parseFloat(val) || 0;
    setCart(prev => prev.map(item => {
      if (item.tempId === id) {
        const netPrice = item.mrp * (1 - disc / 100);
        return { ...item, discount: disc, price: netPrice };
      }
      return item;
    }));
  };

  const handleNetPriceChange = (id: string, val: string) => {
    const net = parseFloat(val) || 0;
    setCart(prev => prev.map(item => {
      if (item.tempId === id) {
        const disc = item.mrp > 0 ? ((item.mrp - net) / item.mrp) * 100 : 0;
        return { ...item, price: net, discount: parseFloat(disc.toFixed(2)) };
      }
      return item;
    }));
  };

  const removeItem = (id: string) => {
    setCart(prev => prev.filter(item => item.tempId !== id));
  };

  const handleSubmit = async () => {
      if (cart.length === 0) return;
      if (mode === 'SALES' && !customerName.trim()) return alert("Customer Name is required.");

      const payload = cart.map(c => ({
          ...c,
          customerName: customerName || (mode === 'PURCHASE' ? 'Manual Supplier' : 'Walk-in'),
          createdByRole: user.role
      }));
      setLoading(true);
      const res = await createBulkTransactions(payload);
      setLoading(false);

      if (res.success) {
          alert(user.role === Role.MANAGER ? "Sent for approval." : "Transaction successful.");
          setCart([]);
          setCustomerName('');
          fetchInventory().then(setInventory);
      } else alert("Error: " + res.message);
  };

  const handleMobileScroll = (e: React.UIEvent<HTMLDivElement>) => {
    const scrollTop = e.currentTarget.scrollTop;
    if (scrollTop > 50 && !hideFilters && suggestions.length > 0) {
      setHideFilters(true);
    } else if (scrollTop < 10 && hideFilters && search.length === 0) {
      setHideFilters(false);
    }
  };

  const totalAmount = cart.reduce((sum, item) => sum + (item.quantity * item.price), 0);
  const accentColor = mode === 'RETURN' ? 'bg-rose-600' : mode === 'PURCHASE' ? 'bg-slate-900' : 'bg-brand-600';

  return (
    <div className="flex-1 h-full flex flex-col animate-fade-in relative overflow-hidden">

       {/* MOBILE SEARCH MODAL - Immersive Full Screen */}
       {showMobileSearch && (
         <div className="fixed inset-0 z-[999] bg-white flex flex-col animate-slide-up h-[100dvh] w-screen overflow-hidden">
            <div className="flex-none h-24 flex items-end px-5 pb-4 gap-4 bg-white border-b border-slate-100 shadow-sm">
               <button onClick={() => { setShowMobileSearch(false); setHideFilters(false); }} className="p-3 text-slate-900 bg-slate-100 rounded-2xl active:scale-90 transition-all">
                  <ArrowLeft size={24} strokeWidth={2.5} />
               </button>
               <div className="flex-1">
                  <h3 className="font-black text-xl text-slate-900 tracking-tight leading-none">Find Spare Part</h3>
                  <p className="text-[10px] font-black text-brand-600 uppercase tracking-[0.2em] mt-1.5">Master Catalog Lookup</p>
               </div>
               <button 
                  onClick={() => setHideFilters(!hideFilters)} 
                  className={`p-3 rounded-2xl transition-all ${hideFilters ? 'text-brand-600 bg-brand-50' : 'text-slate-400 bg-slate-50'}`}
               >
                  <Filter size={20} />
               </button>
            </div>

            <div className={`flex-none bg-white transition-all duration-300 ease-in-out overflow-hidden ${hideFilters ? 'max-h-[84px]' : 'max-h-[160px]'}`}>
                <div className="p-5 space-y-4">
                    <div className="relative group">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-brand-500 transition-colors" size={22} />
                        <input 
                            autoFocus
                            type="text" 
                            className="w-full bg-slate-50 p-4.5 pl-12 rounded-2xl border-none text-[17px] font-bold shadow-inner outline-none ring-1 ring-slate-100 focus:ring-2 focus:ring-brand-500/20 transition-all placeholder:text-slate-300"
                            placeholder="Type part number..."
                            value={search}
                            onChange={e => handleSearch(e.target.value)}
                        />
                        {search && (
                          <button onClick={() => handleSearch('')} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 bg-slate-200/50 p-1.5 rounded-full active:scale-90 transition-all">
                            <X size={18} />
                          </button>
                        )}
                    </div>

                    {!hideFilters && (
                      <div className="flex gap-2 overflow-x-auto no-scrollbar py-1 animate-fade-in">
                          {(['ALL', Brand.HYUNDAI, Brand.MAHINDRA] as const).map(b => (
                              <button
                                  key={b}
                                  onClick={() => { setSelectedBrand(b); handleSearch(search); }}
                                  className={`px-6 py-3 rounded-xl text-[11px] font-black uppercase tracking-widest whitespace-nowrap border-2 transition-all active:scale-95 ${selectedBrand === b ? 'bg-slate-900 text-white border-slate-900 shadow-xl' : 'bg-white text-slate-400 border-slate-100'}`}
                              >
                                  {b}
                              </button>
                          ))}
                      </div>
                    )}
                </div>
            </div>

            <div 
              ref={scrollRef}
              onScroll={handleMobileScroll}
              className="flex-1 overflow-y-auto p-5 space-y-4 no-scrollbar bg-[#F8FAFC]"
            >
                {suggestions.map(item => (
                    <button 
                        key={item.id}
                        onClick={() => addToCart(item)}
                        className="w-full bg-white p-5 rounded-[2.5rem] border border-slate-100 shadow-premium flex justify-between items-center text-left active:scale-[0.97] transition-all group"
                    >
                        <div className="flex-1 min-w-0 pr-4">
                            <div className="flex items-center gap-2 mb-2">
                                <div className={`w-2 h-2 rounded-full ${item.quantity > 0 ? 'bg-teal-500 animate-pulse' : 'bg-rose-500'}`}></div>
                                <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-md ${item.brand === Brand.HYUNDAI ? 'bg-blue-600 text-white' : 'bg-red-600 text-white'}`}>
                                    {item.brand.substring(0,3)}
                                </span>
                                <div className="font-black text-slate-900 text-lg tracking-tight truncate group-active:text-brand-600 transition-colors">{item.partNumber}</div>
                            </div>
                            <div className="text-[13px] text-slate-400 font-bold truncate mb-3 pl-4">{item.name}</div>
                            <div className="flex items-center gap-3 pl-4">
                                <div className="text-[10px] font-black uppercase text-slate-300 tracking-widest">
                                   Stock: <span className={item.quantity > 0 ? 'text-slate-600' : 'text-rose-500'}>{item.quantity} units</span>
                                </div>
                            </div>
                        </div>
                        <div className="text-right flex flex-col items-end gap-3">
                            <div className="font-black text-slate-900 text-xl tracking-tight">₹{item.price.toLocaleString()}</div>
                            <div className="w-12 h-12 bg-brand-600 text-white rounded-2xl shadow-lg shadow-brand-100 flex items-center justify-center group-active:scale-90 transition-all">
                                <Plus size={24} strokeWidth={3} />
                            </div>
                        </div>
                    </button>
                ))}

                {search.length === 0 && (
                   <div className="flex flex-col items-center justify-center py-32 text-slate-300">
                      <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mb-8 shadow-soft animate-pulse">
                        <LayoutGrid size={48} className="opacity-20" />
                      </div>
                      <p className="font-black text-[12px] uppercase tracking-[0.4em] text-slate-400">Inventory Explorer</p>
                      <p className="text-[10px] font-bold text-slate-300 mt-2">Start typing to see matching items</p>
                   </div>
                )}

                {search.length > 1 && suggestions.length === 0 && (
