                  <tbody className="divide-y divide-slate-50">
                     {stats.partImpact.filter(p => p.leakage > 0).map((part, i) => (
                        <tr key={i} className="hover:bg-slate-50/50 transition-colors">
                           <td className="px-6 py-4">
