                              <div className="text-[8px] font-bold text-rose-400 uppercase">Margin Lost</div>
                           </td>
                        </tr>
                     ))}
                  </tbody>
               </table>
            </div>

            {/* Mobile Card View */}
            <div className="md:hidden flex-1 overflow-y-auto max-h-[400px] p-4 space-y-3">
                {stats.partImpact.filter(p => p.leakage > 0).map((part, i) => (
