import { getCustomers } from '../services/masterService';
import { 
  Search,
  Loader2,
  Trash2,
  Minus,
  Plus,
  ShoppingCart,
  User as UserIcon,
  PackagePlus,
  ArrowLeft,
  X,
  AlertCircle,
  Zap,
  ArrowRight,
  RefreshCw,
  IndianRupee,
  ChevronRight,
  Layers
} from 'lucide-react';
import ConfirmModal from '../components/ConfirmModal';

const formatQty = (n: number | string) => {
  const num = typeof n === 'string' ? parseInt(n) : n;
  if (isNaN(num)) return '00';
  const isNeg = num < 0;
  const abs = Math.abs(num);
  const str = abs < 10 ? `0${abs}` : `${abs}`;
  return isNeg ? `-${str}` : str;
};

interface Props {
  user: User;
  forcedMode?: 'SALES' | 'PURCHASE' | 'RETURN';
  onSearchToggle?: (isOpen: boolean) => void;
}

interface CartItem {
  tempId: string;
  partNumber: string;
  name?: string; 
  type: TransactionType;
  quantity: number;
  price: number;
  mrp: number;
  discount: number;
  customerName: string;
}

const DailyTransactions: React.FC<Props> = ({ user, forcedMode, onSearchToggle }) => {
  const [mode, setMode] = useState<'SALES' | 'PURCHASE' | 'RETURN'>(forcedMode || 'SALES');
  const [inventory, setInventory] = useState<StockItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [refreshing, setRefreshing] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [search, setSearch] = useState('');
  const [suggestions, setSuggestions] = useState<StockItem[]>([]);
  const [customerName, setCustomerName] = useState('');
  const [savedCustomers, setSavedCustomers] = useState<Customer[]>([]);
  const [customerSuggestions, setCustomerSuggestions] = useState<Customer[]>([]);
  const [showCustomerList, setShowCustomerList] = useState(false);
  const [showMobileSearch, setShowMobileSearch] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  const loadData = async (isManual = false) => {
    if (isManual) setRefreshing(true);
    try {
      const inv = await fetchInventory();
      setInventory(inv);
      if (mode === 'SALES') {
        const custs = await getCustomers();
        setSavedCustomers(custs);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setRefreshing(false);
    }
  };

  useEffect(() => {
    loadData();
    const handleClickOutside = (e: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(e.target as Node)) setShowCustomerList(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [mode]);

  useEffect(() => {
    if (onSearchToggle) onSearchToggle(showMobileSearch);
  }, [showMobileSearch]);

  const handleSearch = (val: string) => {
    setSearch(val);
    if (val.length > 0) {
       const filtered = inventory.filter(i => 
         i.partNumber.toLowerCase().includes(val.toLowerCase()) || 
         i.name.toLowerCase().includes(val.toLowerCase())
       );
       setSuggestions(filtered.slice(0, 20));
    } else {
       setSuggestions([]);
    }
  };

  const addToCart = (item: StockItem) => {
      const existing = cart.find(c => c.partNumber === item.partNumber);
      if (existing) {
          updateQty(existing.tempId, 1);
          resetSearch();
          return;
      }
      if (mode === 'SALES' && item.quantity === 0) return alert("Out of stock!");

      const initialDiscount = mode === 'PURCHASE' ? 12 : 0;
      const initialPrice = item.price * (1 - initialDiscount / 100);

      const newItem: CartItem = {
          tempId: Math.random().toString(36),
          partNumber: item.partNumber,
          name: item.name, 
          type: mode === 'SALES' ? TransactionType.SALE : mode === 'PURCHASE' ? TransactionType.PURCHASE : TransactionType.RETURN,
          quantity: 1,
          mrp: item.price,
          discount: initialDiscount,
          price: initialPrice,
          customerName: customerName
      };
      setCart(prev => [...prev, newItem]);
      resetSearch();
  };

  const resetSearch = () => {
    setSearch('');
    setSuggestions([]);
    setShowMobileSearch(false);
  };

  const updateQty = (id: string, delta: number) => {
      setCart(prev => prev.map(item => {
          if (item.tempId === id) {
              let newQty = Math.max(1, item.quantity + delta);
              if (mode === 'SALES') {
                  const stock = inventory.find(i => i.partNumber === item.partNumber);
                  if (stock && newQty > stock.quantity) newQty = stock.quantity;
              }
              return { ...item, quantity: newQty };
          }
          return item;
      }));
  };

  const executeSubmit = async () => {
      if (cart.length === 0) return;
      setLoading(true);
      const res = await createBulkTransactions(cart.map(c => ({
          ...c,
          customerName: customerName || (mode === 'PURCHASE' ? 'Supplier' : 'Walk-in'),
          createdByRole: user.role
      })));
      setLoading(false);
      setShowConfirm(false);

      if (res.success) {
          alert("Transaction Successful.");
          setCart([]);
          setCustomerName('');
          loadData();
      } else alert("Error: " + res.message);
  };

  const totalAmount = cart.reduce((sum, item) => sum + (item.quantity * item.price), 0);
  const accentColor = mode === 'RETURN' ? 'bg-rose-600' : mode === 'PURCHASE' ? 'bg-slate-900' : 'bg-brand-600';

  return (
    <div className="flex-1 h-full flex flex-col relative animate-fade-in no-scrollbar overflow-hidden">
       {/* MOBILE REFRESH HEADER */}
       <div className="flex justify-between items-center px-4 py-2 bg-white border-b border-slate-100 lg:hidden">
          <div className="flex items-center gap-2">
             <div className={`w-2 h-2 rounded-full ${refreshing ? 'bg-amber-400 animate-pulse' : 'bg-teal-500'}`}></div>
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{mode} Live</span>
          </div>
          <button 
             onClick={() => loadData(true)}
             disabled={refreshing}
             className={`p-2 rounded-xl text-slate-400 hover:text-brand-600 transition-all ${refreshing ? 'opacity-50' : ''}`}
          >
             <RefreshCw size={16} className={refreshing ? 'animate-spin' : ''} />
          </button>
       </div>

       {/* MOBILE SEARCH OVERLAY */}
       {showMobileSearch && (
         <div className="fixed inset-0 z-[999] bg-slate-50 flex flex-col animate-slide-up h-screen overflow-hidden">
            <div className="h-20 flex items-end px-5 pb-4 gap-4 bg-white border-b border-slate-200">
               <button onClick={() => setShowMobileSearch(false)} className="p-2.5 text-slate-400 bg-slate-50 rounded-xl">
                  <ArrowLeft size={22} />
               </button>
               <div className="flex-1 relative">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                  <input 
                     autoFocus
                     type="text" 
                     className="w-full bg-slate-50 pl-10 pr-4 py-2.5 rounded-xl border-none font-bold text-sm outline-none ring-1 ring-slate-200 focus:ring-2 focus:ring-brand-500/20"
                     placeholder="Search Part Number..."
                     value={search}
                     onChange={e => handleSearch(e.target.value)}
                  />
               </div>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar">
                {suggestions.map(item => (
                    <button 
                        key={item.id}
                        onClick={() => addToCart(item)}
                        className="w-full bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex justify-between items-center text-left active:scale-[0.98]"
                    >
                        <div className="flex-1 min-w-0 pr-4">
                            <div className="flex items-center gap-2 mb-1">
                                <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded ${item.brand === Brand.HYUNDAI ? 'bg-blue-600 text-white' : 'bg-red-600 text-white'}`}>{item.brand}</span>
                                <div className="font-bold text-slate-900 truncate tracking-tight">{item.partNumber}</div>
                            </div>
                            <div className="text-[11px] text-slate-400 truncate">{item.name}</div>
                            <div className="text-[9px] font-black text-slate-300 mt-1 uppercase tracking-widest">Stock: {formatQty(item.quantity)}</div>
                        </div>
                        <div className="text-right">
                            <div className="font-black text-slate-900">₹{item.price.toLocaleString()}</div>
                        </div>
                    </button>
                ))}
            </div>
         </div>
       )}

       {/* DESKTOP VIEW */}
       <div className="hidden lg:grid grid-cols-12 gap-8 h-full p-4">
           <div className="col-span-8 bg-white rounded-[2.5rem] shadow-soft border border-slate-100 flex flex-col overflow-hidden">
               <div className="p-8 bg-slate-50/50 border-b border-slate-100">
                  <div className="relative">
                     <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={24} />
                     <input 
                        type="text" 
                        className="w-full pl-14 pr-6 py-5 bg-white border border-slate-200 rounded-3xl text-xl font-bold focus:ring-4 focus:ring-brand-500/5 outline-none transition-all shadow-inner-soft"
                        placeholder="Search SKU..."
                        value={search}
                        onChange={e => handleSearch(e.target.value)}
                     />
                  </div>
               </div>
               <div className="flex-1 overflow-y-auto p-8 no-scrollbar space-y-4">
                  {suggestions.length > 0 ? (
                    <div className="grid grid-cols-2 gap-4">
                       {suggestions.map(item => (
                          <button key={item.id} onClick={() => addToCart(item)} className="p-6 bg-white border border-slate-100 rounded-3xl hover:border-brand-200 hover:shadow-xl transition-all text-left flex flex-col gap-3 group">
                             <div className="flex justify-between items-start">
                                <span className="font-black text-slate-900 group-hover:text-brand-600 transition-colors">{item.partNumber}</span>
                                <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider ${item.quantity > 0 ? 'bg-teal-50 text-teal-600' : 'bg-rose-50 text-rose-600'}`}>{formatQty(item.quantity)} In Stock</span>
                             </div>
                             <p className="text-sm text-slate-500 truncate">{item.name}</p>
                             <p className="text-xl font-black text-slate-900 mt-2">₹{item.price.toLocaleString()}</p>
                          </button>
                       ))}
                    </div>
                  ) : (
                    <div className="h-full flex flex-col items-center justify-center text-slate-200">
                       <ShoppingCart size={80} className="opacity-10 mb-4" />
                       <p className="text-xs font-black uppercase tracking-[0.3em] text-slate-400">Inventory Scanned</p>
                    </div>
                  )}
               </div>
           </div>

           <div className="col-span-4 bg-white rounded-[2.5rem] shadow-soft border border-slate-100 flex flex-col overflow-visible">
              <div className="p-8 border-b border-slate-50 flex items-center justify-between">
                 <h3 className="font-black text-slate-900 text-lg uppercase tracking-tight flex items-center gap-2">
                    <Layers className="text-brand-600" /> Current Bill
                 </h3>
                 <button onClick={() => setCart([])} className="text-[10px] font-black text-rose-400 uppercase tracking-widest hover:text-rose-600 transition-colors">Reset</button>
              </div>
              <div className="p-8 pb-4">
                 <div className="relative" ref={wrapperRef}>
                    <input 
                       type="text" 
                       className="w-full bg-slate-50 p-4 rounded-2xl border border-slate-100 font-bold outline-none focus:ring-2 focus:ring-brand-500/10"
                       placeholder="Customer / Supplier Name"
                       value={customerName}
                       onChange={e => {
                          setCustomerName(e.target.value);
                          setShowCustomerList(true);
                       }}
                    />
                 </div>
              </div>
              <div className="flex-1 overflow-y-auto p-8 pt-0 space-y-3 no-scrollbar">
                 {cart.map(item => (
