       <ConfirmModal 
          isOpen={showConfirm}
          onClose={() => setShowConfirm(false)}
          onConfirm={executeSubmit}
          loading={loading}
          variant={mode === 'RETURN' ? 'danger' : 'primary'}
          title={`Process ${mode}`}
          message={`Final total is ₹${totalAmount.toLocaleString()}. Continue?`}
       />
    </div>
  );
};

