                            const inCart = cart.some(c => c.partNumber === item.partNumber);
                            return (
                                <div key={item.id} className={`p-4 flex items-center justify-between group transition-all hover:bg-slate-50/80 ${inCart ? 'opacity-40' : ''}`}>
