            <h1 className="text-3xl font-black text-slate-900 tracking-tight leading-none mb-2">
              Profit Intelligence
            </h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.25em]">Financial Audit Ledger v4.2</p>
          </div>
        </div>

