                                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">TOTAL COLLECTED</p>
                                        <p className="text-xl font-black text-teal-600 tabular-nums">₹{group.totalPaid.toLocaleString()}</p>
