  Search,
  Loader2,
  Trash2,
  Minus,
  Plus,
  ShoppingCart,
  User as UserIcon,
  PackagePlus,
  ArrowLeft,
  X,
  ArrowRight,
  Filter,
  Activity,
  Box,
  Percent,
  Calculator,
  Lock,
  History,
  PlusSquare,
  Tag,
