            <div className="p-6">
                <div className="relative group">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={24} strokeWidth={2.5} />
                    <input 
                        autoFocus
                        type="text" 
                        className="w-full bg-slate-100/50 p-5 pl-14 rounded-3xl border-none text-[18px] font-black shadow-inner outline-none placeholder:text-slate-300 uppercase tracking-tight"
