                   <div className="relative group">
                       <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 transition-colors" size={26} strokeWidth={2.5} />
                       <input 
                         type="text" 
                         className="w-full pl-16 pr-6 py-6 bg-white border border-slate-200 rounded-[2.5rem] text-2xl font-black placeholder:text-slate-200 shadow-inner-soft outline-none transition-all uppercase tracking-tight"
                         placeholder="Scan Part Number..."
                         value={search}
                         onChange={e => handleSearch(e.target.value)}
                       />
                   </div>
               </div>
               <div className="flex-1 overflow-y-auto p-8 no-scrollbar">
                  {suggestions.length > 0 ? (
                      <div className="grid grid-cols-2 gap-5">
                         {suggestions.map(item => (
