import React, { useState, useEffect, useMemo } from 'react';
import { User, Transaction, TransactionStatus, TransactionType, Role, PaymentStatus } from '../types';
import DailyTransactions from './DailyTransactions'; 
import { 
  History, 
  PlusCircle, 
  User as UserIcon, 
  Undo2, 
  Search, 
  CheckCircle2, 
  AlertCircle, 
  Clock, 
  Calendar, 
  Minus, 
  Plus, 
  Loader2,
  Filter,
  ArrowUpDown,
  ChevronDown,
  X,
  TrendingDown,
  TrendingUp,
  Banknote,
  Layers,
  List,
  ChevronRight,
  Package,
  ArrowLeft,
  Users,
  Wallet,
  RefreshCw
} from 'lucide-react';
import { createBulkTransactions, fetchTransactions, updateBillPayment } from '../services/transactionService';
import TharLoader from '../components/TharLoader';
import ConfirmModal from '../components/ConfirmModal';

interface Props {
  user: User;
}

type SortField = 'date' | 'amount';
type SortOrder = 'asc' | 'desc';
type ViewMode = 'LIST' | 'STACKED' | 'CUSTOMER';

interface GroupedBill {
  id: string; 
  createdAt: string;
  customerName: string;
  type: TransactionType;
  items: Transaction[];
  totalAmount: number;
  paidAmount: number; // Sum of partial payments
  paymentStatus: PaymentStatus;
}

interface CustomerGroup {
  name: string;
  totalBusiness: number;
  totalPaid: number;
  billsCount: number;
  lastVisit: string;
  bills: GroupedBill[];
}

const Billing: React.FC<Props> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<'NEW' | 'RETURN' | 'HISTORY'>('NEW');
  const [viewMode, setViewMode] = useState<ViewMode>('STACKED');
  const [history, setHistory] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(false);
  const [isSearchingOnMobile, setIsSearchingOnMobile] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  // Modal states
  const [selectedBill, setSelectedBill] = useState<GroupedBill | null>(null);
  const [showReturnConfirm, setShowReturnConfirm] = useState(false);
  const [paymentAmount, setPaymentAmount] = useState<string>('');
  const [isAddingPayment, setIsAddingPayment] = useState(false);

  // --- HISTORY FILTERS & SORTING STATE ---
  const [historySearch, setHistorySearch] = useState('');
  const [typeFilter, setTypeFilter] = useState<'ALL' | TransactionType.SALE | TransactionType.RETURN>('ALL');
  const [dateRange, setDateRange] = useState<'ALL' | 'TODAY' | 'WEEK' | 'MONTH'>('ALL');
  const [minAmount, setMinAmount] = useState<string>('');
  const [maxAmount, setMaxAmount] = useState<string>('');
  const [sortBy, setSortBy] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');

  // --- RETURN TAB STATE ---
  const [salesLog, setSalesLog] = useState<Transaction[]>([]);
  const [returnSearch, setReturnSearch] = useState('');
  const [selectedReturns, setSelectedReturns] = useState<Record<string, number>>({}); 
  const [processingReturns, setProcessingReturns] = useState(false);
  const [alreadyReturnedMap, setAlreadyReturnedMap] = useState<Map<string, number>>(new Map());

  useEffect(() => {
    if (activeTab === 'HISTORY') {
      loadHistory();
    }
    if (activeTab === 'RETURN') {
      loadSalesForReturn();
    }
  }, [activeTab]);

  const loadHistory = async () => {
    setLoading(true);
    const data = await fetchTransactions(
      TransactionStatus.APPROVED, 
      [TransactionType.SALE, TransactionType.RETURN]
    );
    setHistory(data);
    setLoading(false);
  };

  const loadSalesForReturn = async () => {
    setLoading(true);
    const salesData = await fetchTransactions(TransactionStatus.APPROVED, TransactionType.SALE);
    const returnsData = await fetchTransactions(TransactionStatus.APPROVED, TransactionType.RETURN);

    const returnedMap = new Map<string, number>();
    returnsData.forEach(r => {
        if (r.relatedTransactionId) {
            const current = returnedMap.get(r.relatedTransactionId) || 0;
            returnedMap.set(r.relatedTransactionId, current + r.quantity);
        }
    });
    setAlreadyReturnedMap(returnedMap);

    const availableSales = salesData.filter(sale => {
        const returnedQty = returnedMap.get(sale.id) || 0;
        return sale.quantity > returnedQty;
    });

    setSalesLog(availableSales);
    setLoading(false);
  };

  // --- COMPUTED FILTERED HISTORY ---
  const filteredHistory = useMemo(() => {
    let result = [...history];

    if (historySearch) {
      const s = historySearch.toLowerCase();
      result = result.filter(tx => 
        tx.partNumber.toLowerCase().includes(s) || 
        tx.customerName.toLowerCase().includes(s)
      );
    }

    if (typeFilter !== 'ALL') {
      result = result.filter(tx => tx.type === typeFilter);
    }

    if (dateRange !== 'ALL') {
      const now = new Date();
      const startOfToday = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();

      result = result.filter(tx => {
        const txTime = new Date(tx.createdAt).getTime();
        if (dateRange === 'TODAY') return txTime >= startOfToday;
        if (dateRange === 'WEEK') return txTime >= (now.getTime() - 7 * 24 * 60 * 60 * 1000);
        if (dateRange === 'MONTH') return txTime >= (now.getTime() - 30 * 24 * 60 * 60 * 1000);
        return true;
      });
    }

    const min = parseFloat(minAmount);
    const max = parseFloat(maxAmount);
    if (!isNaN(min)) result = result.filter(tx => (tx.price * tx.quantity) >= min);
    if (!isNaN(max)) result = result.filter(tx => (tx.price * tx.quantity) <= max);

    return result;
  }, [history, historySearch, typeFilter, dateRange, minAmount, maxAmount]);

  // --- GROUPING LOGIC FOR STACKED VIEW ---
  const stackedHistory = useMemo(() => {
    const groups: Record<string, GroupedBill> = {};

    filteredHistory.forEach(tx => {
      const key = `${tx.createdAt}_${tx.customerName}_${tx.type}`;
      if (!groups[key]) {
        groups[key] = {
          id: tx.id,
          createdAt: tx.createdAt,
          customerName: tx.customerName,
          type: tx.type,
          items: [],
          totalAmount: 0,
          paidAmount: 0,
          paymentStatus: tx.paymentStatus || 'PAID'
        };
      }
      groups[key].items.push(tx);
      groups[key].totalAmount += (tx.price * tx.quantity);
      groups[key].paidAmount += (tx.paidAmount || 0);
    });

    const result = Object.values(groups);

    result.sort((a, b) => {
      let valA = sortBy === 'date' ? new Date(a.createdAt).getTime() : a.totalAmount;
      let valB = sortBy === 'date' ? new Date(b.createdAt).getTime() : b.totalAmount;

      if (sortOrder === 'asc') return valA - valB;
      return valB - valA;
    });

    return result;
  }, [filteredHistory, sortBy, sortOrder]);

  // --- GROUPING LOGIC FOR CUSTOMER VIEW ---
  const customerHistory = useMemo(() => {
    const groups: Record<string, CustomerGroup> = {};

    stackedHistory.forEach(bill => {
      const name = bill.customerName || 'Walk-in Customer';
      if (!groups[name]) {
        groups[name] = {
          name: name,
          totalBusiness: 0,
          totalPaid: 0,
          billsCount: 0,
          lastVisit: bill.createdAt,
          bills: []
        };
      }
      const group = groups[name];
      group.totalBusiness += bill.totalAmount;
      group.totalPaid += bill.paidAmount;
      group.billsCount += 1;
      if (new Date(bill.createdAt) > new Date(group.lastVisit)) {
        group.lastVisit = bill.createdAt;
      }
      group.bills.push(bill);
    });

    return Object.values(groups).sort((a, b) => b.totalBusiness - a.totalBusiness);
  }, [stackedHistory]);

  const sortedListHistory = useMemo(() => {
    const result = [...filteredHistory];
    result.sort((a, b) => {
      let valA = sortBy === 'date' ? new Date(a.createdAt).getTime() : (a.price * a.quantity);
      let valB = sortBy === 'date' ? new Date(b.createdAt).getTime() : (b.price * b.quantity);
      if (sortOrder === 'asc') return valA - valB;
      return valB - valA;
    });
    return result;
  }, [filteredHistory, sortBy, sortOrder]);

  const handleReturnToggle = (tx: Transaction) => {
    const newSelection = { ...selectedReturns };
    if (newSelection[tx.id]) {
      delete newSelection[tx.id];
    } else {
      const prevReturned = alreadyReturnedMap.get(tx.id) || 0;
      const remaining = tx.quantity - prevReturned;
      newSelection[tx.id] = remaining > 0 ? remaining : 0;
    }
    setSelectedReturns(newSelection);
  };

  const handleReturnQtyChange = (txId: string, maxQty: number, newQty: string) => {
    let qty = parseInt(newQty);
    if (isNaN(qty)) qty = 0;
    if (qty > maxQty) qty = maxQty;
    if (qty < 0) qty = 0;

    if (qty === 0) {
      const newSelection = { ...selectedReturns };
      delete newSelection[txId];
      setSelectedReturns(newSelection);
    } else {
      setSelectedReturns({ ...selectedReturns, [txId]: qty });
    }
  };

  const submitReturns = async () => {
    const ids = Object.keys(selectedReturns);
    if (ids.length === 0) return;

    setProcessingReturns(true);
    const returnPayload = ids.map(id => {
       const originalSale = salesLog.find(s => s.id === id);
       if (!originalSale) return null;
       return {
         partNumber: originalSale.partNumber,
         type: TransactionType.RETURN,
         quantity: selectedReturns[id],
         price: originalSale.price,
         customerName: originalSale.customerName || 'Customer Return',
         createdByRole: user.role,
         relatedTransactionId: originalSale.id
       };
    }).filter(Boolean) as any[];

    const res = await createBulkTransactions(returnPayload);
    setProcessingReturns(false);
    setShowReturnConfirm(false);

    if (res.success) {
       alert("Returns processed successfully.");
       setSelectedReturns({});
       loadSalesForReturn();
    } else {
       alert("Failed to process returns: " + res.message);
    }
  };

  const handleBillPaymentUpdate = async () => {
    if (!selectedBill) return;
    const amount = parseFloat(paymentAmount);
    if (isNaN(amount) || amount <= 0) return alert("Enter a valid collection amount");

    setLoading(true);
    const res = await updateBillPayment(selectedBill.createdAt, selectedBill.customerName, amount);
    setLoading(false);

    if (res.success) {
      alert("Collection record updated.");
      setPaymentAmount('');
      setIsAddingPayment(false);
      setSelectedBill(null);
      loadHistory();
    } else {
      alert("Update failed: " + res.message);
    }
  };

  const clearFilters = () => {
    setHistorySearch('');
    setTypeFilter('ALL');
    setDateRange('ALL');
    setMinAmount('');
    setMaxAmount('');
    setSortBy('date');
    setSortOrder('desc');
  };

  return (
    <div className="h-full flex flex-col bg-slate-50 md:bg-transparent">

       {!isSearchingOnMobile && (
         <div className="md:hidden bg-white p-4 border-b border-slate-100 z-20 sticky top-0 shadow-sm animate-fade-in">
            <div className="flex bg-slate-100 p-1 rounded-2xl">
               <button onClick={() => setActiveTab('NEW')} className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'NEW' ? 'bg-white text-brand-600 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}>POS</button>
               <button onClick={() => setActiveTab('RETURN')} className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'RETURN' ? 'bg-white text-rose-600 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}>Returns</button>
               <button onClick={() => setActiveTab('HISTORY')} className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'HISTORY' ? 'bg-white text-slate-800 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}>History</button>
            </div>
         </div>
       )}

       <div className="hidden md:flex justify-between items-center mb-6">
          <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Counter Ledger</h1>
             <p className="text-slate-500 font-medium">Record sales and verify customer collections.</p>
          </div>
          <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-soft">
             <button onClick={() => setActiveTab('NEW')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'NEW' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <PlusCircle size={18} /> New Entry
             </button>
             <button onClick={() => setActiveTab('RETURN')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'RETURN' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <Undo2 size={18} /> Return
             </button>
             <button onClick={() => setActiveTab('HISTORY')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'HISTORY' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <History size={18} /> Journal
             </button>
          </div>
       </div>

       <div className="flex-1 overflow-hidden flex flex-col relative">
          {activeTab === 'NEW' && <DailyTransactions user={user} forcedMode="SALES" onSearchToggle={setIsSearchingOnMobile} />}

          {activeTab === 'RETURN' && (
             <div className="bg-[#F8FAFC] md:bg-white md:rounded-3xl shadow-soft border border-slate-100 flex flex-col h-full overflow-hidden">
                <div className="p-4 md:p-6 border-b border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-4">
                   <div className="flex items-center gap-3 text-rose-600 font-black text-base w-full md:w-auto">
                      <div className="p-2 bg-rose-50 rounded-xl"><Undo2 size={20} /></div>
                      STOCK RETURN SELECTOR
                   </div>
                   <div className="w-full md:w-auto flex-1 md:max-w-xs relative">
                       <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                       <input 
                          type="text" 
                          placeholder="Search Bill/Part..."
                          className="w-full pl-11 pr-4 py-3 bg-slate-50 border-none rounded-2xl text-sm font-bold shadow-inner"
                          value={returnSearch}
                          onChange={e => setReturnSearch(e.target.value)}
                       />
                   </div>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar pb-24">
                   {loading ? <TharLoader /> : (
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                        {salesLog.filter(tx => tx.partNumber.toLowerCase().includes(returnSearch.toLowerCase()) || tx.customerName.toLowerCase().includes(returnSearch.toLowerCase())).map(tx => {
                            const isSelected = !!selectedReturns[tx.id];
                            const prevReturned = alreadyReturnedMap.get(tx.id) || 0;
                            const remainingQty = tx.quantity - prevReturned;
                            return (
                                <div key={tx.id} onClick={() => handleReturnToggle(tx)} className={`p-5 rounded-[2rem] border transition-all cursor-pointer bg-white ${isSelected ? 'border-rose-500 ring-2 ring-rose-500/10 shadow-lg' : 'border-slate-100 hover:border-slate-200'}`}>
                                    <div className="flex justify-between items-start mb-4">
                                        <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${isSelected ? 'bg-rose-50 border-rose-50 text-white' : 'bg-slate-50 border-slate-200 text-transparent'}`}><CheckCircle2 size={14} /></div>
                                        <div className="text-right text-[11px] font-bold text-slate-900">{new Date(tx.createdAt).toLocaleDateString()}</div>
                                    </div>
                                    <div className="mb-4">
                                        <div className="font-black text-lg text-slate-900 leading-tight">{tx.partNumber}</div>
                                        <div className="text-[13px] text-slate-400 font-medium truncate mt-1">{tx.customerName || 'Retail'}</div>
                                    </div>
                                    {isSelected && (
                                        <div onClick={e => e.stopPropagation()} className="bg-rose-50 p-2 rounded-2xl border border-rose-100 flex flex-col items-center">
                                            <span className="text-[9px] font-black text-rose-500 uppercase mb-1">Qty to Return</span>
                                            <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl shadow-sm">
                                                <button onClick={() => handleReturnQtyChange(tx.id, remainingQty, (selectedReturns[tx.id] - 1).toString())} className="w-8 h-8 flex items-center justify-center text-rose-500"><Minus size={14}/></button>
                                                <span className="font-black text-slate-900 min-w-[20px] text-center">{selectedReturns[tx.id]}</span>
                                                <button onClick={() => handleReturnQtyChange(tx.id, remainingQty, (selectedReturns[tx.id] + 1).toString())} className="w-8 h-8 bg-rose-500 text-white rounded-lg flex items-center justify-center"><Plus size={14}/></button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            )
                        })}
                      </div>
                   )}
                </div>

                <div className="fixed bottom-0 md:bottom-6 left-0 right-0 md:left-auto md:right-8 bg-white md:rounded-3xl border-t md:border border-slate-100 p-5 shadow-2xl z-[90] flex justify-between items-center md:min-w-[400px]">
                   <div className="flex-1">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Refund Total</p>
                      <p className="text-2xl font-black text-rose-600 tracking-tight">₹{totalRefundAmount.toLocaleString()}</p>
                   </div>
                   <button onClick={() => setShowReturnConfirm(true)} disabled={Object.keys(selectedReturns).length === 0 || processingReturns} className="bg-rose-600 hover:bg-rose-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl active:scale-[0.95] disabled:opacity-30">Commit Return</button>
                </div>
             </div>
          )}

          {activeTab === 'HISTORY' && (
             <div className="bg-[#F8FAFC] md:bg-white md:rounded-3xl shadow-soft border border-slate-100 flex flex-col h-full overflow-hidden">
                <div className="p-4 md:p-6 border-b border-slate-100 bg-white flex flex-col lg:flex-row justify-between items-center gap-4">
                   <div className="flex items-center gap-3 w-full md:w-auto">
                      <div className="p-2 bg-slate-900 text-white rounded-xl"><History size={18} /></div>
                      <span className="font-black text-slate-900 text-base uppercase tracking-tight">Transaction History</span>
                      <div className="ml-4 flex bg-slate-100 p-1 rounded-xl shadow-inner">
                          <button onClick={() => setViewMode('STACKED')} className={`p-2 rounded-lg transition-all ${viewMode === 'STACKED' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400'}`}><Layers size={16} /></button>
                          <button onClick={() => setViewMode('CUSTOMER')} className={`p-2 rounded-lg transition-all ${viewMode === 'CUSTOMER' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400'}`}><Users size={16} /></button>
                          <button onClick={() => setViewMode('LIST')} className={`p-2 rounded-lg transition-all ${viewMode === 'LIST' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400'}`}><List size={16} /></button>
                      </div>
                   </div>
                   <div className="flex items-center gap-2 w-full md:w-auto">
                      <div className="relative flex-1 md:w-64">
                         <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                         <input type="text" placeholder="Filter..." className="w-full pl-10 pr-4 py-2 bg-slate-50 border-none rounded-xl text-sm font-bold shadow-inner" value={historySearch} onChange={e => setHistorySearch(e.target.value)} />
                      </div>
                      <button onClick={loadHistory} className="p-2 bg-white text-slate-400 border border-slate-200 rounded-xl hover:text-slate-600"><RefreshCw size={16} /></button>
                   </div>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar pb-24">
                  {loading ? <TharLoader /> : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                      {viewMode === 'STACKED' && stackedHistory.map(bill => (
                        <div key={bill.id} onClick={() => setSelectedBill(bill)} className="p-6 rounded-[2.5rem] bg-white border-2 border-slate-100 shadow-soft hover:border-brand-100 hover:shadow-xl transition-all cursor-pointer group relative animate-fade-in">
                            <div className="flex justify-between items-start mb-6">
                                <div className="space-y-1.5">
                                    <div className={`px-2.5 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest w-fit ${bill.type === 'RETURN' ? 'bg-rose-50 text-rose-600' : 'bg-teal-50 text-teal-600'}`}>{bill.type}</div>
                                    <div className="text-[11px] font-bold text-slate-400 flex items-center gap-2"><Calendar size={12}/> {new Date(bill.createdAt).toLocaleDateString()}</div>
                                </div>
                                <div className="flex flex-col items-end gap-2">
                                    <ChevronRight size={20} className="text-slate-300 group-hover:text-brand-600 transition-colors" />
                                    {bill.type === 'SALE' && (
                                        <span className={`text-[8px] font-black px-2 py-0.5 rounded uppercase tracking-widest ${bill.paymentStatus === 'PENDING' ? (bill.paidAmount > 0 ? 'bg-amber-100 text-amber-600' : 'bg-rose-100 text-rose-600') : 'bg-teal-100 text-teal-600'}`}>
                                            {bill.paymentStatus === 'PENDING' ? (bill.paidAmount > 0 ? 'PARTIAL' : 'CREDIT') : 'PAID'}
                                        </span>
                                    )}
                                </div>
                            </div>
                            <div className="mb-6">
                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Customer</p>
                                <div className="font-black text-lg text-slate-900 leading-tight truncate group-hover:text-brand-600 transition-colors">{bill.customerName || 'Retail'}</div>
                            </div>
                            <div className="flex justify-between items-end border-t border-slate-50 pt-5">
                                <div className="text-[11px] font-black text-slate-500 uppercase tracking-widest">{bill.items.length} Parts</div>
                                <div className="text-right">
                                    <p className="text-[9px] font-black text-slate-400 uppercase mb-0.5">Total</p>
                                    <p className={`text-2xl font-black tracking-tighter ${bill.type === 'RETURN' ? 'text-rose-600' : 'text-slate-900'}`}>₹{bill.totalAmount.toLocaleString()}</p>
                                </div>
                            </div>
                        </div>
                      ))}

                      {viewMode === 'CUSTOMER' && customerHistory.map(group => (
                        <div key={group.name} className="p-8 rounded-[3rem] bg-white border-2 border-slate-100 shadow-soft hover:shadow-xl transition-all animate-fade-in group">
                            <div className="flex items-center gap-5 mb-8">
                                <div className="w-16 h-16 bg-slate-100 rounded-[1.75rem] flex items-center justify-center text-slate-500 group-hover:bg-brand-50 group-hover:text-brand-600 transition-all shadow-inner"><UserIcon size={32} /></div>
                                <div className="flex-1 min-w-0">
                                    <h3 className="font-black text-slate-900 text-xl truncate tracking-tight uppercase leading-none mb-2">{group.name}</h3>
                                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">Visit: {new Date(group.lastVisit).toLocaleDateString()}</div>
                                </div>
                            </div>
                            <div className="grid grid-cols-2 gap-4 mb-8">
                                <div className="bg-slate-50 p-4 rounded-2xl text-center">
                                    <p className="text-[9px] font-black text-slate-400 uppercase mb-1">TOTAL BUSINESS</p>
                                    <p className="text-xl font-black text-slate-900">₹{group.totalBusiness.toLocaleString()}</p>
                                </div>
                                <div className="bg-slate-50 p-4 rounded-2xl text-center">
                                    <p className="text-[9px] font-black text-slate-400 uppercase mb-1">BALANCE DUE</p>
                                    <p className={`text-xl font-black ${group.totalBusiness - group.totalPaid > 0 ? 'text-rose-600' : 'text-teal-600'}`}>₹{(group.totalBusiness - group.totalPaid).toLocaleString()}</p>
                                </div>
                            </div>
                            <button onClick={() => { setHistorySearch(group.name); setViewMode('STACKED'); }} className="w-full py-4 bg-slate-900 hover:bg-brand-600 text-white font-black rounded-2xl transition-all text-[11px] uppercase tracking-widest shadow-lg">Browse Bills</button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
             </div>
          )}
       </div>

       {/* BILL DETAIL MODAL */}
       {selectedBill && (
          <div className="fixed inset-0 z-[200] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 lg:p-8 animate-fade-in">
              <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl flex flex-col max-h-[90vh] overflow-hidden animate-slide-up">
                  <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/40">
                      <div className="flex items-center gap-5">
                          <button onClick={() => { setSelectedBill(null); setIsAddingPayment(false); }} className="p-3 bg-white text-slate-400 hover:text-slate-900 rounded-2xl border border-slate-100 active:scale-90 transition-all"><ArrowLeft size={24}/></button>
                          <div>
                              <h3 className="font-black text-slate-900 text-2xl tracking-tight leading-none mb-2">{selectedBill.customerName || 'Cash Sale'}</h3>
                              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">{new Date(selectedBill.createdAt).toLocaleString()}</p>
                          </div>
                      </div>
                      <div className={`px-5 py-2.5 rounded-2xl text-sm font-black uppercase tracking-widest border-2 ${selectedBill.paymentStatus === 'PENDING' ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-teal-50 text-teal-600 border-teal-100'}`}>
                          {selectedBill.paymentStatus === 'PENDING' ? (selectedBill.paidAmount > 0 ? 'PARTIAL' : 'CREDIT') : 'PAID'}
                      </div>
                  </div>

                  <div className="flex-1 overflow-y-auto p-6 md:p-10 no-scrollbar space-y-6">
                      <div className="space-y-3">
                          {selectedBill.items.map((item, idx) => (
                              <div key={item.id} className="p-6 bg-slate-50/50 rounded-3xl border border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
                                  <div className="flex items-center gap-5">
                                      <div className="w-10 h-10 bg-white rounded-xl border border-slate-100 flex items-center justify-center font-black text-slate-300 text-sm">{idx + 1}</div>
                                      <div className="min-w-0">
                                          <div className="font-black text-slate-900 text-lg leading-tight uppercase truncate">{item.partNumber}</div>
                                          <p className="text-[13px] text-slate-400 font-bold uppercase mt-1">Rate: ₹{item.price.toLocaleString()}</p>
                                      </div>
                                  </div>
                                  <div className="flex items-center justify-between md:justify-end gap-12 border-t md:border-t-0 border-slate-100 pt-4 md:pt-0">
                                      <div className="text-right"><p className="text-[9px] font-black text-slate-300 uppercase mb-0.5">Qty</p><p className="text-xl font-black text-slate-900">{item.quantity}</p></div>
                                      <div className="text-right"><p className="text-[9px] font-black text-slate-300 uppercase mb-0.5">Subtotal</p><p className="text-xl font-black text-slate-900 tracking-tight">₹{(item.price * item.quantity).toLocaleString()}</p></div>
                                  </div>
                              </div>
                          ))}
                      </div>

                      {selectedBill.paymentStatus === 'PENDING' && !isAddingPayment && (
                          <button onClick={() => setIsAddingPayment(true)} className="w-full py-6 border-2 border-dashed border-brand-200 text-brand-600 rounded-3xl font-black uppercase text-xs tracking-widest hover:bg-brand-50 transition-all flex items-center justify-center gap-3"><Wallet size={18}/> Add New Collection / Payment</button>
                      )}

                      {isAddingPayment && (
                          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-elevated animate-fade-in">
                              <div className="flex justify-between items-center mb-6">
                                  <h4 className="font-black uppercase text-xs tracking-[0.2em] text-white/40">Record Follow-up Payment</h4>
                                  <button onClick={() => setIsAddingPayment(false)} className="text-white/20 hover:text-white"><X size={20}/></button>
                              </div>
                              <div className="flex flex-col md:flex-row gap-6 items-end">
                                  <div className="flex-1 space-y-2">
                                      <label className="text-[10px] font-black uppercase tracking-widest text-white/30 ml-2">Amount Collected (₹)</label>
                                      <div className="relative">
                                          <IndianRupee className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" size={20} />
                                          <input autoFocus type="number" placeholder="0.00" className="w-full bg-white/5 border border-white/10 rounded-2xl pl-12 pr-4 py-4 text-2xl font-black text-white focus:border-brand-500/50 outline-none" value={paymentAmount} onChange={e => setPaymentAmount(e.target.value)} />
                                      </div>
                                  </div>
                                  <button onClick={handleBillPaymentUpdate} className="bg-brand-600 hover:bg-brand-500 text-white font-black px-10 py-5 rounded-2xl active:scale-95 transition-all text-xs uppercase tracking-widest">Post Collection</button>
                              </div>
                              <p className="mt-6 text-[10px] font-black text-white/30 uppercase tracking-[0.1em] text-center">Remaining Balance: ₹{(selectedBill.totalAmount - selectedBill.paidAmount).toLocaleString()}</p>
                          </div>
                      )}
                  </div>

                  <div className="p-8 md:p-10 border-t border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-6">
                      <div className="flex flex-col md:flex-row items-center gap-10">
                          <div className="flex items-center gap-5">
                             <div className="p-4 bg-slate-900 text-white rounded-3xl shadow-xl"><Banknote size={32} /></div>
                             <div>
                                 <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Bill Amount</p>
                                 <p className="text-4xl font-black tracking-tighter text-slate-900">₹{selectedBill.totalAmount.toLocaleString()}</p>
                             </div>
                          </div>
                          {selectedBill.type === 'SALE' && (
                            <div className="flex flex-col border-l border-slate-100 pl-10 h-full justify-center">
                                <div className="flex items-center gap-3 mb-2"><span className="text-[10px] font-black text-teal-600 uppercase">Received</span><span className="font-black text-slate-900 text-lg">₹{selectedBill.paidAmount.toLocaleString()}</span></div>
                                <div className="flex items-center gap-3"><span className="text-[10px] font-black text-rose-50 uppercase">Balance</span><span className="font-black text-rose-600 text-lg">₹{(selectedBill.totalAmount - selectedBill.paidAmount).toLocaleString()}</span></div>
                            </div>
                          )}
                      </div>
                      <button onClick={() => { setSelectedBill(null); setIsAddingPayment(false); }} className="w-full md:w-auto bg-slate-100 hover:bg-slate-200 text-slate-600 font-black px-12 py-5 rounded-[2rem] uppercase text-xs tracking-widest">Close</button>
                  </div>
              </div>
          </div>
       )}

       <ConfirmModal isOpen={showReturnConfirm} onClose={() => setShowReturnConfirm(false)} onConfirm={submitReturns} loading={processingReturns} variant="danger" title="Confirm Return" message={`Process return for ${Object.keys(selectedReturns).length} items? Total refund: ₹${totalRefundAmount.toLocaleString()}.`} confirmLabel="Proceed" />
    </div>
  );
};

export default Billing;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Transaction, TransactionStatus, TransactionType, Role, PaymentStatus } from '../types';
import DailyTransactions from './DailyTransactions'; 
import { 
  History, 
  PlusCircle, 
  User as UserIcon, 
  Undo2, 
  Search, 
  CheckCircle2, 
  AlertCircle, 
  Clock, 
  Calendar, 
  Minus, 
  Plus, 
  Loader2,
  Filter,
  ArrowUpDown,
  ChevronDown,
  X,
  TrendingDown,
  TrendingUp,
  Banknote,
  Layers,
  List,
  ChevronRight,
  Package,
  ArrowLeft,
  Users,
  Wallet,
  RefreshCw,
  // Added IndianRupee icon to imports
  IndianRupee
} from 'lucide-react';
import { createBulkTransactions, fetchTransactions, updateBillPayment } from '../services/transactionService';
import TharLoader from '../components/TharLoader';
import ConfirmModal from '../components/ConfirmModal';

interface Props {
  user: User;
}

type SortField = 'date' | 'amount';
type SortOrder = 'asc' | 'desc';
type ViewMode = 'LIST' | 'STACKED' | 'CUSTOMER';

interface GroupedBill {
  id: string; 
  createdAt: string;
  customerName: string;
  type: TransactionType;
  items: Transaction[];
  totalAmount: number;
  paidAmount: number; // Sum of partial payments
  paymentStatus: PaymentStatus;
}

interface CustomerGroup {
  name: string;
  totalBusiness: number;
  totalPaid: number;
  billsCount: number;
  lastVisit: string;
  bills: GroupedBill[];
}

const Billing: React.FC<Props> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<'NEW' | 'RETURN' | 'HISTORY'>('NEW');
  const [viewMode, setViewMode] = useState<ViewMode>('STACKED');
  const [history, setHistory] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(false);
  const [isSearchingOnMobile, setIsSearchingOnMobile] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  // Modal states
  const [selectedBill, setSelectedBill] = useState<GroupedBill | null>(null);
  const [showReturnConfirm, setShowReturnConfirm] = useState(false);
  const [paymentAmount, setPaymentAmount] = useState<string>('');
  const [isAddingPayment, setIsAddingPayment] = useState(false);

  // --- HISTORY FILTERS & SORTING STATE ---
  const [historySearch, setHistorySearch] = useState('');
  const [typeFilter, setTypeFilter] = useState<'ALL' | TransactionType.SALE | TransactionType.RETURN>('ALL');
  const [dateRange, setDateRange] = useState<'ALL' | 'TODAY' | 'WEEK' | 'MONTH'>('ALL');
  const [minAmount, setMinAmount] = useState<string>('');
  const [maxAmount, setMaxAmount] = useState<string>('');
  const [sortBy, setSortBy] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');

  // --- RETURN TAB STATE ---
  const [salesLog, setSalesLog] = useState<Transaction[]>([]);
  const [returnSearch, setReturnSearch] = useState('');
  const [selectedReturns, setSelectedReturns] = useState<Record<string, number>>({}); 
  const [processingReturns, setProcessingReturns] = useState(false);
  const [alreadyReturnedMap, setAlreadyReturnedMap] = useState<Map<string, number>>(new Map());

  // Added calculation for total refund amount to fix "Cannot find name 'totalRefundAmount'" error
  const totalRefundAmount = useMemo(() => {
    return Object.keys(selectedReturns).reduce((sum, id) => {
      const tx = salesLog.find(s => s.id === id);
      return sum + (tx ? tx.price * selectedReturns[id] : 0);
    }, 0);
  }, [selectedReturns, salesLog]);

  useEffect(() => {
    if (activeTab === 'HISTORY') {
      loadHistory();
    }
    if (activeTab === 'RETURN') {
      loadSalesForReturn();
    }
  }, [activeTab]);

  const loadHistory = async () => {
    setLoading(true);
    const data = await fetchTransactions(
      TransactionStatus.APPROVED, 
      [TransactionType.SALE, TransactionType.RETURN]
    );
    setHistory(data);
    setLoading(false);
  };

  const loadSalesForReturn = async () => {
    setLoading(true);
    const salesData = await fetchTransactions(TransactionStatus.APPROVED, TransactionType.SALE);
    const returnsData = await fetchTransactions(TransactionStatus.APPROVED, TransactionType.RETURN);

    const returnedMap = new Map<string, number>();
    returnsData.forEach(r => {
        if (r.relatedTransactionId) {
            const current = returnedMap.get(r.relatedTransactionId) || 0;
            returnedMap.set(r.relatedTransactionId, current + r.quantity);
        }
    });
    setAlreadyReturnedMap(returnedMap);

    const availableSales = salesData.filter(sale => {
        const returnedQty = returnedMap.get(sale.id) || 0;
        return sale.quantity > returnedQty;
    });

    setSalesLog(availableSales);
    setLoading(false);
  };

  // --- COMPUTED FILTERED HISTORY ---
  const filteredHistory = useMemo(() => {
    let result = [...history];

    if (historySearch) {
      const s = historySearch.toLowerCase();
      result = result.filter(tx => 
        tx.partNumber.toLowerCase().includes(s) || 
        tx.customerName.toLowerCase().includes(s)
      );
    }

    if (typeFilter !== 'ALL') {
      result = result.filter(tx => tx.type === typeFilter);
    }

    if (dateRange !== 'ALL') {
      const now = new Date();
      const startOfToday = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();

      result = result.filter(tx => {
        const txTime = new Date(tx.createdAt).getTime();
        if (dateRange === 'TODAY') return txTime >= startOfToday;
        if (dateRange === 'WEEK') return txTime >= (now.getTime() - 7 * 24 * 60 * 60 * 1000);
        if (dateRange === 'MONTH') return txTime >= (now.getTime() - 30 * 24 * 60 * 60 * 1000);
        return true;
      });
    }

    const min = parseFloat(minAmount);
    const max = parseFloat(maxAmount);
    if (!isNaN(min)) result = result.filter(tx => (tx.price * tx.quantity) >= min);
    if (!isNaN(max)) result = result.filter(tx => (tx.price * tx.quantity) <= max);

    return result;
  }, [history, historySearch, typeFilter, dateRange, minAmount, maxAmount]);

  // --- GROUPING LOGIC FOR STACKED VIEW ---
  const stackedHistory = useMemo(() => {
    const groups: Record<string, GroupedBill> = {};

    filteredHistory.forEach(tx => {
      const key = `${tx.createdAt}_${tx.customerName}_${tx.type}`;
      if (!groups[key]) {
        groups[key] = {
          id: tx.id,
          createdAt: tx.createdAt,
          customerName: tx.customerName,
          type: tx.type,
          items: [],
          totalAmount: 0,
          paidAmount: 0,
          paymentStatus: tx.paymentStatus || 'PAID'
        };
      }
      groups[key].items.push(tx);
      groups[key].totalAmount += (tx.price * tx.quantity);
      groups[key].paidAmount += (tx.paidAmount || 0);
    });

    const result = Object.values(groups);

    result.sort((a, b) => {
      let valA = sortBy === 'date' ? new Date(a.createdAt).getTime() : a.totalAmount;
      let valB = sortBy === 'date' ? new Date(b.createdAt).getTime() : b.totalAmount;

      if (sortOrder === 'asc') return valA - valB;
      return valB - valA;
    });

    return result;
  }, [filteredHistory, sortBy, sortOrder]);

  // --- GROUPING LOGIC FOR CUSTOMER VIEW ---
  const customerHistory = useMemo(() => {
    const groups: Record<string, CustomerGroup> = {};

    stackedHistory.forEach(bill => {
      const name = bill.customerName || 'Walk-in Customer';
      if (!groups[name]) {
        groups[name] = {
          name: name,
          totalBusiness: 0,
          totalPaid: 0,
          billsCount: 0,
          lastVisit: bill.createdAt,
          bills: []
        };
      }
      const group = groups[name];
      group.totalBusiness += bill.totalAmount;
      group.totalPaid += bill.paidAmount;
      group.billsCount += 1;
      if (new Date(bill.createdAt) > new Date(group.lastVisit)) {
        group.lastVisit = bill.createdAt;
      }
      group.bills.push(bill);
    });

    return Object.values(groups).sort((a, b) => b.totalBusiness - a.totalBusiness);
  }, [stackedHistory]);

  const sortedListHistory = useMemo(() => {
    const result = [...filteredHistory];
    result.sort((a, b) => {
      let valA = sortBy === 'date' ? new Date(a.createdAt).getTime() : (a.price * a.quantity);
      let valB = sortBy === 'date' ? new Date(b.createdAt).getTime() : (b.price * b.quantity);
      if (sortOrder === 'asc') return valA - valB;
      return valB - valA;
    });
    return result;
  }, [filteredHistory, sortBy, sortOrder]);

  const handleReturnToggle = (tx: Transaction) => {
    const newSelection = { ...selectedReturns };
    if (newSelection[tx.id]) {
      delete newSelection[tx.id];
    } else {
      const prevReturned = alreadyReturnedMap.get(tx.id) || 0;
      const remaining = tx.quantity - prevReturned;
      newSelection[tx.id] = remaining > 0 ? remaining : 0;
    }
    setSelectedReturns(newSelection);
  };

  const handleReturnQtyChange = (txId: string, maxQty: number, newQty: string) => {
    let qty = parseInt(newQty);
    if (isNaN(qty)) qty = 0;
    if (qty > maxQty) qty = maxQty;
    if (qty < 0) qty = 0;

    if (qty === 0) {
      const newSelection = { ...selectedReturns };
      delete newSelection[txId];
      setSelectedReturns(newSelection);
    } else {
      setSelectedReturns({ ...selectedReturns, [txId]: qty });
    }
  };

  const submitReturns = async () => {
    const ids = Object.keys(selectedReturns);
    if (ids.length === 0) return;

    setProcessingReturns(true);
    const returnPayload = ids.map(id => {
       const originalSale = salesLog.find(s => s.id === id);
       if (!originalSale) return null;
       return {
         partNumber: originalSale.partNumber,
         type: TransactionType.RETURN,
         quantity: selectedReturns[id],
         price: originalSale.price,
         customerName: originalSale.customerName || 'Customer Return',
         createdByRole: user.role,
         relatedTransactionId: originalSale.id
       };
    }).filter(Boolean) as any[];

    const res = await createBulkTransactions(returnPayload);
    setProcessingReturns(false);
    setShowReturnConfirm(false);

    if (res.success) {
       alert("Returns processed successfully.");
       setSelectedReturns({});
       loadSalesForReturn();
    } else {
       alert("Failed to process returns: " + res.message);
    }
  };

  const handleBillPaymentUpdate = async () => {
    if (!selectedBill) return;
    const amount = parseFloat(paymentAmount);
    if (isNaN(amount) || amount <= 0) return alert("Enter a valid collection amount");

    setLoading(true);
    const res = await updateBillPayment(selectedBill.createdAt, selectedBill.customerName, amount);
    setLoading(false);

    if (res.success) {
      alert("Collection record updated.");
      setPaymentAmount('');
      setIsAddingPayment(false);
      setSelectedBill(null);
      loadHistory();
    } else {
      alert("Update failed: " + res.message);
    }
  };

  const clearFilters = () => {
    setHistorySearch('');
    setTypeFilter('ALL');
    setDateRange('ALL');
    setMinAmount('');
    setMaxAmount('');
    setSortBy('date');
    setSortOrder('desc');
  };

  return (
    <div className="h-full flex flex-col bg-slate-50 md:bg-transparent">

       {!isSearchingOnMobile && (
         <div className="md:hidden bg-white p-4 border-b border-slate-100 z-20 sticky top-0 shadow-sm animate-fade-in">
            <div className="flex bg-slate-100 p-1 rounded-2xl">
               <button onClick={() => setActiveTab('NEW')} className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'NEW' ? 'bg-white text-brand-600 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}>POS</button>
               <button onClick={() => setActiveTab('RETURN')} className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'RETURN' ? 'bg-white text-rose-600 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}>Returns</button>
               <button onClick={() => setActiveTab('HISTORY')} className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'HISTORY' ? 'bg-white text-slate-800 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}>History</button>
            </div>
         </div>
       )}

       <div className="hidden md:flex justify-between items-center mb-6">
          <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Counter Ledger</h1>
             <p className="text-slate-500 font-medium">Record sales and verify customer collections.</p>
          </div>
          <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-soft">
             <button onClick={() => setActiveTab('NEW')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'NEW' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <PlusCircle size={18} /> New Entry
             </button>
             <button onClick={() => setActiveTab('RETURN')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'RETURN' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <Undo2 size={18} /> Return
             </button>
             <button onClick={() => setActiveTab('HISTORY')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'HISTORY' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <History size={18} /> Journal
             </button>
          </div>
       </div>

       <div className="flex-1 overflow-hidden flex flex-col relative">
          {activeTab === 'NEW' && <DailyTransactions user={user} forcedMode="SALES" onSearchToggle={setIsSearchingOnMobile} />}

          {activeTab === 'RETURN' && (
             <div className="bg-[#F8FAFC] md:bg-white md:rounded-3xl shadow-soft border border-slate-100 flex flex-col h-full overflow-hidden">
                <div className="p-4 md:p-6 border-b border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-4">
                   <div className="flex items-center gap-3 text-rose-600 font-black text-base w-full md:w-auto">
                      <div className="p-2 bg-rose-50 rounded-xl"><Undo2 size={20} /></div>
                      STOCK RETURN SELECTOR
                   </div>
                   <div className="w-full md:w-auto flex-1 md:max-w-xs relative">
                       <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                       <input 
                          type="text" 
                          placeholder="Search Bill/Part..."
                          className="w-full pl-11 pr-4 py-3 bg-slate-50 border-none rounded-2xl text-sm font-bold shadow-inner"
                          value={returnSearch}
                          onChange={e => setReturnSearch(e.target.value)}
                       />
                   </div>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar pb-24">
                   {loading ? <TharLoader /> : (
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                        {salesLog.filter(tx => tx.partNumber.toLowerCase().includes(returnSearch.toLowerCase()) || tx.customerName.toLowerCase().includes(returnSearch.toLowerCase())).map(tx => {
                            const isSelected = !!selectedReturns[tx.id];
                            const prevReturned = alreadyReturnedMap.get(tx.id) || 0;
                            const remainingQty = tx.quantity - prevReturned;
                            return (
                                <div key={tx.id} onClick={() => handleReturnToggle(tx)} className={`p-5 rounded-[2rem] border transition-all cursor-pointer bg-white ${isSelected ? 'border-rose-500 ring-2 ring-rose-500/10 shadow-lg' : 'border-slate-100 hover:border-slate-200'}`}>
                                    <div className="flex justify-between items-start mb-4">
                                        <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${isSelected ? 'bg-rose-50 border-rose-50 text-white' : 'bg-slate-50 border-slate-200 text-transparent'}`}><CheckCircle2 size={14} /></div>
                                        <div className="text-right text-[11px] font-bold text-slate-900">{new Date(tx.createdAt).toLocaleDateString()}</div>
                                    </div>
                                    <div className="mb-4">
                                        <div className="font-black text-lg text-slate-900 leading-tight">{tx.partNumber}</div>
                                        <div className="text-[13px] text-slate-400 font-medium truncate mt-1">{tx.customerName || 'Retail'}</div>
                                    </div>
                                    {isSelected && (
                                        <div onClick={e => e.stopPropagation()} className="bg-rose-50 p-2 rounded-2xl border border-rose-100 flex flex-col items-center">
                                            <span className="text-[9px] font-black text-rose-500 uppercase mb-1">Qty to Return</span>
                                            <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl shadow-sm">
                                                <button onClick={() => handleReturnQtyChange(tx.id, remainingQty, (selectedReturns[tx.id] - 1).toString())} className="w-8 h-8 flex items-center justify-center text-rose-500"><Minus size={14}/></button>
                                                <span className="font-black text-slate-900 min-w-[20px] text-center">{selectedReturns[tx.id]}</span>
                                                <button onClick={() => handleReturnQtyChange(tx.id, remainingQty, (selectedReturns[tx.id] + 1).toString())} className="w-8 h-8 bg-rose-500 text-white rounded-lg flex items-center justify-center"><Plus size={14}/></button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            )
                        })}
                      </div>
                   )}
                </div>

                <div className="fixed bottom-0 md:bottom-6 left-0 right-0 md:left-auto md:right-8 bg-white md:rounded-3xl border-t md:border border-slate-100 p-5 shadow-2xl z-[90] flex justify-between items-center md:min-w-[400px]">
                   <div className="flex-1">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Refund Total</p>
                      <p className="text-2xl font-black text-rose-600 tracking-tight">₹{totalRefundAmount.toLocaleString()}</p>
                   </div>
                   <button onClick={() => setShowReturnConfirm(true)} disabled={Object.keys(selectedReturns).length === 0 || processingReturns} className="bg-rose-600 hover:bg-rose-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl active:scale-[0.95] disabled:opacity-30">Commit Return</button>
                </div>
             </div>
          )}

          {activeTab === 'HISTORY' && (
             <div className="bg-[#F8FAFC] md:bg-white md:rounded-3xl shadow-soft border border-slate-100 flex flex-col h-full overflow-hidden">
                <div className="p-4 md:p-6 border-b border-slate-100 bg-white flex flex-col lg:flex-row justify-between items-center gap-4">
                   <div className="flex items-center gap-3 w-full md:w-auto">
                      <div className="p-2 bg-slate-900 text-white rounded-xl"><History size={18} /></div>
                      <span className="font-black text-slate-900 text-base uppercase tracking-tight">Transaction History</span>
                      <div className="ml-4 flex bg-slate-100 p-1 rounded-xl shadow-inner">
                          <button onClick={() => setViewMode('STACKED')} className={`p-2 rounded-lg transition-all ${viewMode === 'STACKED' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400'}`}><Layers size={16} /></button>
                          <button onClick={() => setViewMode('CUSTOMER')} className={`p-2 rounded-lg transition-all ${viewMode === 'CUSTOMER' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400'}`}><Users size={16} /></button>
                          <button onClick={() => setViewMode('LIST')} className={`p-2 rounded-lg transition-all ${viewMode === 'LIST' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400'}`}><List size={16} /></button>
                      </div>
                   </div>
                   <div className="flex items-center gap-2 w-full md:w-auto">
                      <div className="relative flex-1 md:w-64">
                         <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                         <input type="text" placeholder="Filter..." className="w-full pl-10 pr-4 py-2 bg-slate-50 border-none rounded-xl text-sm font-bold shadow-inner" value={historySearch} onChange={e => setHistorySearch(e.target.value)} />
                      </div>
                      <button onClick={loadHistory} className="p-2 bg-white text-slate-400 border border-slate-200 rounded-xl hover:text-slate-600"><RefreshCw size={16} /></button>
                   </div>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar pb-24">
                  {loading ? <TharLoader /> : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                      {viewMode === 'STACKED' && stackedHistory.map(bill => (
                        <div key={bill.id} onClick={() => setSelectedBill(bill)} className="p-6 rounded-[2.5rem] bg-white border-2 border-slate-100 shadow-soft hover:border-brand-100 hover:shadow-xl transition-all cursor-pointer group relative animate-fade-in">
                            <div className="flex justify-between items-start mb-6">
                                <div className="space-y-1.5">
                                    <div className={`px-2.5 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest w-fit ${bill.type === 'RETURN' ? 'bg-rose-50 text-rose-600' : 'bg-teal-50 text-teal-600'}`}>{bill.type}</div>
                                    <div className="text-[11px] font-bold text-slate-400 flex items-center gap-2"><Calendar size={12}/> {new Date(bill.createdAt).toLocaleDateString()}</div>
                                </div>
                                <div className="flex flex-col items-end gap-2">
                                    <ChevronRight size={20} className="text-slate-300 group-hover:text-brand-600 transition-colors" />
                                    {bill.type === 'SALE' && (
                                        <span className={`text-[8px] font-black px-2 py-0.5 rounded uppercase tracking-widest ${bill.paymentStatus === 'PENDING' ? (bill.paidAmount > 0 ? 'bg-amber-100 text-amber-600' : 'bg-rose-100 text-rose-600') : 'bg-teal-100 text-teal-600'}`}>
                                            {bill.paymentStatus === 'PENDING' ? (bill.paidAmount > 0 ? 'PARTIAL' : 'CREDIT') : 'PAID'}
                                        </span>
                                    )}
                                </div>
                            </div>
                            <div className="mb-6">
                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Customer</p>
                                <div className="font-black text-lg text-slate-900 leading-tight truncate group-hover:text-brand-600 transition-colors">{bill.customerName || 'Retail'}</div>
                            </div>
                            <div className="flex justify-between items-end border-t border-slate-50 pt-5">
                                <div className="text-[11px] font-black text-slate-500 uppercase tracking-widest">{bill.items.length} Parts</div>
                                <div className="text-right">
                                    <p className="text-[9px] font-black text-slate-400 uppercase mb-0.5">Total</p>
                                    <p className={`text-2xl font-black tracking-tighter ${bill.type === 'RETURN' ? 'text-rose-600' : 'text-slate-900'}`}>₹{bill.totalAmount.toLocaleString()}</p>
                                </div>
                            </div>
                        </div>
                      ))}

                      {viewMode === 'CUSTOMER' && customerHistory.map(group => (
                        <div key={group.name} className="p-8 rounded-[3rem] bg-white border-2 border-slate-100 shadow-soft hover:shadow-xl transition-all animate-fade-in group">
                            <div className="flex items-center gap-5 mb-8">
                                <div className="w-16 h-16 bg-slate-100 rounded-[1.75rem] flex items-center justify-center text-slate-500 group-hover:bg-brand-50 group-hover:text-brand-600 transition-all shadow-inner"><UserIcon size={32} /></div>
                                <div className="flex-1 min-w-0">
                                    <h3 className="font-black text-slate-900 text-xl truncate tracking-tight uppercase leading-none mb-2">{group.name}</h3>
                                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">Visit: {new Date(group.lastVisit).toLocaleDateString()}</div>
                                </div>
                            </div>
                            <div className="grid grid-cols-2 gap-4 mb-8">
                                <div className="bg-slate-50 p-4 rounded-2xl text-center">
                                    <p className="text-[9px] font-black text-slate-400 uppercase mb-1">TOTAL BUSINESS</p>
                                    <p className="text-xl font-black text-slate-900">₹{group.totalBusiness.toLocaleString()}</p>
                                </div>
                                <div className="bg-slate-50 p-4 rounded-2xl text-center">
                                    <p className="text-[9px] font-black text-slate-400 uppercase mb-1">BALANCE DUE</p>
