       <ConfirmModal isOpen={showReturnConfirm} onClose={() => setShowReturnConfirm(false)} onConfirm={submitReturns} loading={processingReturns} variant="danger" title="Confirm Return" message={`Process return for ${Object.keys(selectedReturns).length} items? Total refund: ₹${totalRefundAmount.toLocaleString()}.`} confirmLabel="Proceed" />
