                                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2 tracking-widest">Aggregate Sales</p>
                                    <p className="text-xl font-black text-slate-900 tabular-nums">₹{group.totalBusiness.toLocaleString()}</p>
                                </div>
                                <div className="bg-slate-50/50 p-5 rounded-[1.5rem] text-center border border-slate-100">
                                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2 tracking-widest">Outstanding</p>
                                    <p className={`text-xl font-black tabular-nums ${group.totalBusiness - group.totalPaid > 0 ? 'text-rose-600' : 'text-teal-600'}`}>₹{(group.totalBusiness - group.totalPaid).toLocaleString()}</p>
                                </div>
                            </div>
                            <button onClick={() => { setHistorySearch(group.name); setViewMode('STACKED'); }} className="w-full py-5 bg-slate-900 hover:bg-blue-600 text-white font-black rounded-2xl transition-all active:scale-[0.98] text-[12px] uppercase tracking-[0.2em] shadow-xl shadow-slate-200 flex items-center justify-center gap-3">Browse Client Ledger <ArrowRight size={18}/></button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
             </div>
          )}
       </div>

       {/* BILL DETAIL & PAYMENT UPDATE MODAL */}
       {selectedBill && (
          <div className="fixed inset-0 z-[200] bg-slate-900/70 backdrop-blur-md flex items-center justify-center p-4 lg:p-8 animate-fade-in overflow-hidden">
              <div className="bg-white w-full max-w-4xl rounded-[3.5rem] shadow-2xl flex flex-col max-h-[90vh] overflow-hidden animate-slide-up relative">
                  <div className="p-8 md:p-10 border-b border-slate-100 flex justify-between items-center bg-white sticky top-0 z-10">
                      <div className="flex items-center gap-6">
                          <button onClick={() => { setSelectedBill(null); setIsAddingPayment(false); }} className="p-4 bg-slate-50 text-slate-400 hover:text-slate-900 rounded-2xl border border-slate-100 active:scale-90 transition-all shadow-soft"><ArrowLeft size={24}/></button>
                          <div>
                              <h3 className="font-black text-slate-900 text-2xl tracking-tight leading-none mb-2 uppercase">{selectedBill.customerName || 'Standard Sale'}</h3>
                              <p className="text-slate-400 text-xs font-black uppercase tracking-[0.2em] flex items-center gap-2"><Clock size={12} className="opacity-40"/> {new Date(selectedBill.createdAt).toLocaleString()}</p>
                          </div>
                      </div>
                      <div className={`px-6 py-3 rounded-2xl text-[12px] font-black uppercase tracking-widest border-2 shadow-sm ${selectedBill.paymentStatus === 'PENDING' ? (selectedBill.paidAmount > 0 ? 'bg-amber-50 text-amber-600 border-amber-100' : 'bg-rose-50 text-rose-600 border-rose-100') : 'bg-teal-50 text-teal-600 border-teal-100'}`}>
                          {selectedBill.paymentStatus === 'PENDING' ? (selectedBill.paidAmount > 0 ? 'Partial Settlement' : 'Credit Protocol') : 'Fully Settled'}
                      </div>
                  </div>

                  <div className="flex-1 overflow-y-auto p-6 md:p-10 no-scrollbar space-y-10 bg-slate-50/20">
                      <div className="space-y-3">
                          <div className="flex items-center gap-3 px-2 mb-4">
                             <Package size={16} className="text-slate-400" />
                             <h4 className="font-black text-[11px] uppercase tracking-[0.2em] text-slate-400">Inventory Disposition</h4>
                          </div>
                          {selectedBill.items.map((item, idx) => (
                              <div key={item.id} className="p-6 bg-white rounded-3xl border border-slate-200/80 shadow-soft flex flex-col md:flex-row md:items-center justify-between gap-6 hover:border-blue-200 transition-colors group">
                                  <div className="flex items-center gap-5">
                                      <div className="w-12 h-12 bg-slate-50 rounded-2xl border border-slate-100 flex items-center justify-center font-black text-slate-300 text-sm group-hover:bg-blue-50 group-hover:text-blue-400 transition-colors">{idx + 1}</div>
                                      <div className="min-w-0">
                                          <div className="font-black text-slate-900 text-xl leading-none uppercase truncate tracking-tight mb-2">{item.partNumber}</div>
                                          <p className="text-[12px] text-slate-400 font-bold uppercase tracking-widest">Rate: ₹{item.price.toLocaleString()}</p>
                                      </div>
                                  </div>
                                  <div className="flex items-center justify-between md:justify-end gap-14 border-t md:border-t-0 border-slate-100 pt-6 md:pt-0">
                                      <div className="text-right"><p className="text-[9px] font-black text-slate-300 uppercase mb-1 tracking-widest">Quantity</p><p className="text-xl font-black text-slate-900 tabular-nums">{item.quantity} PCS</p></div>
                                      <div className="text-right"><p className="text-[9px] font-black text-slate-300 uppercase mb-1 tracking-widest">Total Asset</p><p className="text-2xl font-black text-slate-900 tracking-tighter tabular-nums">₹{(item.price * item.quantity).toLocaleString()}</p></div>
                                  </div>
                              </div>
                          ))}
                      </div>

                      {selectedBill.type === 'SALE' && selectedBill.paymentStatus === 'PENDING' && !isAddingPayment && (
                          <div className="animate-fade-in p-1">
                             <button onClick={() => setIsAddingPayment(true)} className="w-full py-8 border-4 border-dashed border-slate-200 text-slate-400 rounded-[2.5rem] font-black uppercase text-[13px] tracking-[0.25em] hover:bg-blue-50 hover:text-blue-600 hover:border-blue-200 transition-all flex items-center justify-center gap-4 bg-white/50 active:scale-[0.99]"><Wallet size={24}/> Record Collection Detail</button>
                          </div>
                      )}

                      {isAddingPayment && (
                          <div className="bg-[#1E293B] p-10 rounded-[3rem] text-white shadow-2xl shadow-slate-400 animate-slide-up border border-white/5">
                              <div className="flex justify-between items-center mb-10">
                                  <div className="flex items-center gap-4">
                                     <div className="p-3 bg-blue-600 rounded-2xl shadow-xl shadow-blue-500/20"><Wallet size={20} /></div>
                                     <h4 className="font-black uppercase text-[12px] tracking-[0.2em]">Post Payment Record</h4>
                                  </div>
                                  <button onClick={() => setIsAddingPayment(false)} className="p-2 text-white/20 hover:text-white transition-colors bg-white/5 rounded-xl"><X size={24}/></button>
                              </div>
                              <div className="flex flex-col md:flex-row gap-8 items-end">
                                  <div className="flex-1 w-full space-y-3">
                                      <label className="text-[10px] font-black uppercase tracking-widest text-white/30 ml-2">Custom Amount Received (₹)</label>
                                      <div className="relative group">
                                          <IndianRupee className="absolute left-5 top-1/2 -translate-y-1/2 text-white/10 group-focus-within:text-blue-400 transition-colors" size={28} strokeWidth={2.5} />
                                          <input autoFocus type="number" placeholder="0.00" className="w-full bg-black/40 border-2 border-white/5 rounded-3xl pl-16 pr-6 py-6 text-3xl font-black text-white focus:border-blue-500/40 outline-none transition-all shadow-inner" value={paymentAmount} onChange={e => setPaymentAmount(e.target.value)} />
                                      </div>
                                  </div>
                                  <button onClick={handleBillPaymentUpdate} disabled={updatingPayment} className="w-full md:w-auto bg-blue-600 hover:bg-blue-500 text-white font-black px-14 py-7 rounded-[1.75rem] active:scale-95 transition-all text-[14px] uppercase tracking-widest shadow-elevated shadow-blue-900/40 flex items-center justify-center gap-3"> {updatingPayment ? <Loader2 className="animate-spin" /> : <CheckCircle2 size={20} />} Authorize Ledger</button>
                              </div>
                              <div className="mt-10 flex items-center justify-between px-2 py-4 border-t border-white/5">
                                 <p className="text-[10px] font-black text-white/20 uppercase tracking-[0.2em]">Remaining Liability</p>
                                 <p className="text-xl font-black text-rose-400 tabular-nums">₹{(selectedBill.totalAmount - selectedBill.paidAmount).toLocaleString()}</p>
                              </div>
                          </div>
                      )}
                  </div>

                  <div className="p-8 md:p-12 border-t border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-8 sticky bottom-0 z-10 shadow-inner-soft">
                      <div className="flex flex-col md:flex-row items-center gap-12">
                          <div className="flex items-center gap-6">
                             <div className="p-5 bg-slate-900 text-white rounded-3xl shadow-xl shadow-slate-200"><Banknote size={40} strokeWidth={2.5}/></div>
                             <div>
                                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Gross Bill Value</p>
                                 <p className="text-4xl font-black tracking-tighter text-slate-900 tabular-nums">₹{selectedBill.totalAmount.toLocaleString()}</p>
                             </div>
                          </div>
                          {selectedBill.type === 'SALE' && (
                            <div className="flex items-center gap-12 border-l border-slate-100 pl-12 h-16">
                                <div className="flex flex-col justify-center">
                                    <span className="text-[10px] font-black text-teal-600 uppercase tracking-widest mb-1">Settled</span>
                                    <span className="font-black text-slate-900 text-2xl tracking-tight tabular-nums">₹{selectedBill.paidAmount.toLocaleString()}</span>
                                </div>
                                <div className="flex flex-col justify-center">
                                    <span className="text-[10px] font-black text-rose-500 uppercase tracking-widest mb-1">Balance</span>
                                    <span className="font-black text-rose-600 text-2xl tracking-tight tabular-nums">₹{(selectedBill.totalAmount - selectedBill.paidAmount).toLocaleString()}</span>
                                </div>
                            </div>
                          )}
                      </div>
                      <button onClick={() => { setSelectedBill(null); setIsAddingPayment(false); }} className="w-full md:w-auto bg-slate-100 hover:bg-slate-200 text-slate-500 font-black px-16 py-6 rounded-[2rem] uppercase text-[12px] tracking-[0.2em] transition-all active:scale-95">Dismiss Detail</button>
                  </div>
              </div>
          </div>
       )}

       <ConfirmModal isOpen={showReturnConfirm} onClose={() => setShowReturnConfirm(false)} onConfirm={submitReturns} loading={processingReturns} variant="danger" title="Confirm Reversal" message={`Finalizing reversal for ${Object.keys(selectedReturns).length} items. Total cash refund liability is ₹${totalRefundAmount.toLocaleString()}. Proceed with stock restoration?`} confirmLabel="Finalize Return" />
    </div>
  );
};

export default Billing;

import React, { useEffect, useState, useRef } from 'react';
import { Role, TransactionType, User, StockItem, Customer, Brand, TransactionStatus, PaymentStatus } from '../types';
import { createBulkTransactions, fetchTransactions } from '../services/transactionService';
import { fetchInventory, updateOrAddItems } from '../services/inventoryService';
import { getCustomers } from '../services/masterService';
import { 
  Search,
  Loader2,
  Trash2,
  Minus,
  Plus,
  ShoppingCart,
  User as UserIcon,
  PackagePlus,
  ArrowLeft,
  X,
  ArrowRight,
  Filter,
  Activity,
  Box,
  Percent,
  Calculator,
  Lock,
  History,
  PlusSquare,
  Tag,
  Layers,
  Sparkles,
  IndianRupee,
  CheckCircle2,
  AlertCircle,
  Banknote
} from 'lucide-react';
import ConfirmModal from '../components/ConfirmModal';

const formatQty = (n: number | string) => {
  const num = parseInt(n.toString()) || 0;
  return num >= 0 && num < 10 ? `0${num}` : `${num}`;
};

interface Props {
  user: User;
  forcedMode?: 'SALES' | 'PURCHASE' | 'RETURN';
  onSearchToggle?: (isOpen: boolean) => void;
}

interface CartItem {
  tempId: string;
  partNumber: string;
  name?: string; 
  type: TransactionType;
  quantity: number;
  price: number;
  mrp: number;
  discount: number;
  customerName: string;
  stockError?: boolean;
  isNewSku?: boolean; 
  brand?: Brand;
}

const DailyTransactions: React.FC<Props> = ({ user, forcedMode, onSearchToggle }) => {
  const [mode, setMode] = useState<'SALES' | 'PURCHASE' | 'RETURN'>(forcedMode || 'SALES');
  const [inventory, setInventory] = useState<StockItem[]>([]);
  const [pendingSalesMap, setPendingSalesMap] = useState<Record<string, number>>({});
  const [loading, setLoading] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [search, setSearch] = useState('');
  const [suggestions, setSuggestions] = useState<StockItem[]>([]);
  const [customerName, setCustomerName] = useState('');
  const [savedCustomers, setSavedCustomers] = useState<Customer[]>([]);
  const [customerSuggestions, setCustomerSuggestions] = useState<Customer[]>([]);
  const [showCustomerList, setShowCustomerList] = useState(false);
  const [selectedBrand, setSelectedBrand] = useState<Brand | 'ALL'>('ALL');
  const wrapperRef = useRef<HTMLDivElement>(null);
  const [showMobileSearch, setShowMobileSearch] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  // Settlement State
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('PAID');
  const [receivedAmount, setReceivedAmount] = useState<string>('');

  // New SKU State
  const [isAddingNewSku, setIsAddingNewSku] = useState(false);
  const [newSkuForm, setNewSkuForm] = useState({
      partNumber: '',
      name: '',
      mrp: '',
      brand: Brand.HYUNDAI
  });

  useEffect(() => {
    loadBaseData();
    const handleClickOutside = (e: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(e.target as Node)) setShowCustomerList(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [mode]);

  const loadBaseData = async () => {
    const [inv, customers] = await Promise.all([
      fetchInventory(),
      mode === 'SALES' ? getCustomers() : Promise.resolve([])
    ]);
    setInventory(inv);
    if (Array.isArray(customers)) setSavedCustomers(customers);

    const pendingSales = await fetchTransactions(TransactionStatus.PENDING, TransactionType.SALE);
    const pMap: Record<string, number> = {};
    pendingSales.forEach(tx => {
      const pn = tx.partNumber.toLowerCase();
      pMap[pn] = (pMap[pn] || 0) + tx.quantity;
    });
    setPendingSalesMap(pMap);
  };

  useEffect(() => { if (forcedMode) setMode(forcedMode); }, [forcedMode]);

  useEffect(() => {
    if (onSearchToggle) onSearchToggle(showMobileSearch);
  }, [showMobileSearch, onSearchToggle]);

  const handleSearch = (val: string) => {
    setSearch(val);
    if (val.length > 0) {
       let filtered = inventory.filter(i => 
         i.partNumber.toLowerCase().includes(val.toLowerCase()) || 
         i.name.toLowerCase().includes(val.toLowerCase())
       );
       if (selectedBrand !== 'ALL') filtered = filtered.filter(i => i.brand === selectedBrand);
       setSuggestions(filtered.slice(0, 30));
    } else {
       setSuggestions([]);
    }
  };

  const handleCustomerType = (val: string) => {
    setCustomerName(val);
    if (mode === 'SALES' && val.length > 0) {
      const lowerVal = val.toLowerCase();
      setCustomerSuggestions(savedCustomers.filter(c => 
        (c.name?.toLowerCase().includes(lowerVal)) || (c.phone?.includes(val))
      ).slice(0, 5));
      setShowCustomerList(true);
    } else setShowCustomerList(false);
  };

  const getAvailableStock = (item: StockItem) => {
    const pending = pendingSalesMap[item.partNumber.toLowerCase()] || 0;
    return Math.max(0, item.quantity - pending);
  };

  const addToCart = (item: StockItem) => {
      const existing = cart.find(c => c.partNumber === item.partNumber);
      const available = getAvailableStock(item);
      if (existing) {
          if (mode === 'SALES' && existing.quantity + 1 > available) {
            alert(`Insufficient stock. Available: ${available}`);
            return;
          }
          updateQty(existing.tempId, 1);
          resetSearch();
          return;
      }
      if (mode === 'SALES' && available === 0) return alert("Item out of stock!");
      const initialDiscount = mode === 'PURCHASE' ? 12 : 0;
      const initialPrice = mode === 'PURCHASE' ? item.price * 0.88 : item.price;
      const newItem: CartItem = {
          tempId: Math.random().toString(36).substring(2),
          partNumber: item.partNumber,
          name: item.name, 
          type: mode === 'SALES' ? TransactionType.SALE : mode === 'PURCHASE' ? TransactionType.PURCHASE : TransactionType.RETURN,
          quantity: 1,
          mrp: item.price,
          discount: initialDiscount,
          price: initialPrice,
          customerName: customerName,
          stockError: false
      };
      setCart(prev => [...prev, newItem]);
      resetSearch();
  };

  const openNewSkuModal = () => {
      setNewSkuForm({
          ...newSkuForm,
          partNumber: search.toUpperCase(),
          brand: search.toUpperCase().startsWith('MH') ? Brand.MAHINDRA : Brand.HYUNDAI
      });
      setIsAddingNewSku(true);
  };

  const confirmAddNewSku = () => {
      if (!newSkuForm.partNumber || !newSkuForm.name || !newSkuForm.mrp) return alert("Missing required fields.");
      const mrpValue = parseFloat(newSkuForm.mrp);
      if (isNaN(mrpValue)) return alert("Invalid price.");
      const newItem: CartItem = {
          tempId: Math.random().toString(36).substring(2),
          partNumber: newSkuForm.partNumber.toUpperCase().trim(),
          name: newSkuForm.name.toUpperCase(),
          type: TransactionType.PURCHASE,
          quantity: 1,
          mrp: mrpValue,
          discount: 12,
          price: mrpValue * 0.88,
          customerName: customerName || 'Direct Acquisition',
          isNewSku: true,
          brand: newSkuForm.brand
      };
      setCart(prev => [...prev, newItem]);
      setIsAddingNewSku(false);
      resetSearch();
  };

  const resetSearch = () => { setSearch(''); setSuggestions([]); setShowMobileSearch(false); };

  const updateQty = (id: string, delta: number) => {
      setCart(prev => prev.map(item => {
          if (item.tempId === id) {
              let newQty = item.quantity + delta;
              if (newQty < 1) newQty = 1;
              if (mode === 'SALES') {
                  const stockItem = inventory.find(i => i.partNumber === item.partNumber);
                  if (stockItem) {
                    const available = getAvailableStock(stockItem);
                    if (newQty > available) newQty = available;
                  }
              }
              return { ...item, quantity: newQty };
          }
          return item;
      }));
  };

  const removeItem = (id: string) => { setCart(prev => prev.filter(item => item.tempId !== id)); };

  const handleDiscountChange = (id: string, val: string) => {
    const disc = parseFloat(val) || 0;
    setCart(prev => prev.map(item => {
      if (item.tempId === id) {
        const netPrice = item.mrp * (1 - disc / 100);
        return { ...item, discount: disc, price: netPrice };
      }
      return item;
    }));
  };

  const handleNetPriceChange = (id: string, val: string) => {
    const net = parseFloat(val) || 0;
    setCart(prev => prev.map(item => {
      if (item.tempId === id) {
        const disc = item.mrp > 0 ? ((item.mrp - net) / item.mrp) * 100 : 0;
        return { ...item, price: net, discount: parseFloat(disc.toFixed(2)) };
      }
      return item;
    }));
  };

  const totalAmount = cart.reduce((sum, item) => sum + (item.quantity * item.price), 0);

  useEffect(() => {
    if (paymentStatus === 'PAID') setReceivedAmount(totalAmount.toString());
    else setReceivedAmount('0');
  }, [paymentStatus, totalAmount]);

  const executeSubmit = async () => {
      setLoading(true);
      const newItems = cart.filter(c => c.isNewSku);
      if (newItems.length > 0) {
          const payload = newItems.map(c => ({ partNumber: c.partNumber, name: c.name, price: c.mrp, brand: c.brand, quantity: 0 }));
          await updateOrAddItems(payload);
      }
      const receivedNum = parseFloat(receivedAmount) || 0;
      const finalPaymentStatus = (receivedNum >= totalAmount) ? 'PAID' : 'PENDING';
      const payload = cart.map(c => {
          const itemTotal = c.quantity * c.price;
          const proportion = totalAmount > 0 ? itemTotal / totalAmount : 0;
          return {
            ...c,
            customerName: customerName || (mode === 'PURCHASE' ? 'Standard Supplier' : 'Walk-in'),
            createdByRole: user.role,
            paymentStatus: mode === 'SALES' ? finalPaymentStatus : 'PAID',
            paidAmount: mode === 'SALES' ? (receivedNum * proportion) : itemTotal
          };
      });
      const res = await createBulkTransactions(payload);
      setLoading(false);
      setShowConfirm(false);
      if (res.success) {
          alert(user.role === Role.MANAGER ? "Sent to owner for verification." : "Registry updated. Goods moved.");
          setCart([]); setCustomerName(''); setReceivedAmount(''); loadBaseData();
      } else alert("Error: " + res.message);
  };

  const accentColor = mode === 'RETURN' ? 'bg-rose-600' : mode === 'PURCHASE' ? 'bg-slate-900' : 'bg-brand-600';

  return (
    <div className="flex-1 h-full flex flex-col animate-fade-in overflow-hidden">
       {isAddingNewSku && (
         <div className="fixed inset-0 z-[1100] bg-slate-900/70 backdrop-blur-md flex items-center justify-center p-4 lg:p-6 animate-fade-in">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-100 animate-slide-up">
                <div className="p-8 pb-4">
                    <div className="flex items-center gap-5 mb-8">
                        <div className="p-3.5 bg-blue-50 text-blue-600 rounded-[1.25rem] shadow-inner"><Sparkles size={24} strokeWidth={2.5} /></div>
                        <div>
                            <h3 className="text-xl font-black text-slate-900 tracking-tight">Initialize SKU</h3>
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-0.5">Database Registry Entry</p>
                        </div>
                    </div>
                    <div className="space-y-5">
                        <div>
                            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Part ID</label>
                            <input type="text" className="w-full bg-slate-50 p-4 rounded-2xl border-none outline-none font-black text-slate-900 focus:ring-4 focus:ring-blue-500/5 transition-all uppercase shadow-inner-soft" value={newSkuForm.partNumber} onChange={e => setNewSkuForm({...newSkuForm, partNumber: e.target.value})} />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Description</label>
                            <input type="text" placeholder="e.g. OIL FILTER" className="w-full bg-slate-50 p-4 rounded-2xl border-none outline-none font-black text-slate-900 focus:ring-4 focus:ring-blue-500/5 transition-all uppercase shadow-inner-soft" value={newSkuForm.name} onChange={e => setNewSkuForm({...newSkuForm, name: e.target.value})} />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Brand</label>
                                <select className="w-full bg-slate-50 p-4 rounded-2xl border-none outline-none font-black text-slate-900 shadow-inner-soft appearance-none" value={newSkuForm.brand} onChange={e => setNewSkuForm({...newSkuForm, brand: e.target.value as Brand})}><option value={Brand.HYUNDAI}>HYUNDAI</option><option value={Brand.MAHINDRA}>MAHINDRA</option></select>
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">MRP (₹)</label>
                                <input type="number" className="w-full bg-slate-50 p-4 rounded-2xl border-none outline-none font-black text-slate-900 shadow-inner-soft" value={newSkuForm.mrp} onChange={e => setNewSkuForm({...newSkuForm, mrp: e.target.value})} />
                            </div>
                        </div>
                    </div>
                </div>
                <div className="p-6 bg-slate-50 flex gap-3 mt-6">
