                                    <div className="mb-6"><div className="font-black text-xl text-slate-900 tracking-tight leading-none uppercase mb-2">{tx.partNumber}</div><div className="text-[14px] text-slate-400 font-bold truncate">{tx.customerName || 'Walk-in'}</div></div>
                                    <div className="flex justify-between items-end border-t border-slate-50 pt-5">
