                                            <div onClick={e => e.stopPropagation()} className="bg-rose-50 p-3 rounded-2xl border border-rose-100 flex flex-col items-center"><span className="text-[10px] font-black text-rose-500 uppercase mb-2">Adjust</span><div className="flex items-center gap-4 bg-white p-1 rounded-xl shadow-soft">
