                                                <button onClick={() => handleReturnQtyChange(tx.id, remainingQty, (selectedReturns[tx.id] + 1).toString())} className="w-8 h-8 bg-rose-600 text-white rounded-lg flex items-center justify-center"><Plus size={16}/></button>
                                            </div></div>
                                        )}
                                    </div>
                                </div>
                            )
                        })}
                      </div>
