                <div className="fixed bottom-0 md:bottom-8 left-0 right-0 md:left-auto md:right-10 bg-white md:rounded-[2.5rem] border-t md:border border-slate-100 p-6 md:p-8 shadow-2xl z-[90] flex justify-between items-center md:min-w-[450px]">
                   <div className="flex-1">
                      <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5">Refund Total</p>
                      <p className="text-3xl font-black text-rose-600 tracking-tighter tabular-nums">₹{totalRefundAmount.toLocaleString()}</p>
