import { supabase } from './supabase';
import { Invoice, Role, Transaction, TransactionStatus, TransactionType, RequestStatus, PaymentStatus, StockItem } from '../types';

const TX_STORAGE_KEY = 'sparezy_transactions_v1';
const INV_STORAGE_KEY = 'sparezy_inventory_v1';

// --- HELPERS ---

const mapDBToTransaction = (item: any): Transaction => ({
  id: item.id,
  partNumber: item.part_number.toUpperCase(),
  type: item.type as TransactionType,
  quantity: item.quantity,
  price: item.price,
  paidAmount: item.paid_amount,
  customerName: item.customer_name,
  status: item.status as TransactionStatus,
  paymentStatus: item.payment_status as PaymentStatus,
  createdByRole: item.created_by_role as Role,
  createdAt: item.created_at,
  relatedTransactionId: item.related_transaction_id,
  invoiceId: item.invoice_id
});

// --- CORE FUNCTIONS ---

export const createTransaction = async (
  transaction: Omit<Transaction, 'id' | 'status' | 'createdAt'>
): Promise<{ success: boolean; message?: string }> => {
  return createBulkTransactions([transaction]);
};

export const createBulkTransactions = async (
  transactions: Omit<Transaction, 'id' | 'status' | 'createdAt'>[]
): Promise<{ success: boolean; message?: string }> => {
  const createdByRole = transactions[0].createdByRole;

  // Logic: SALES and RETURNS are physical movements.
  // We mark them APPROVED immediately so stock updates even for Managers.
  const getInitialStatus = (type: TransactionType) => {
    if (createdByRole === Role.OWNER) return TransactionStatus.APPROVED;
    if (type === TransactionType.SALE || type === TransactionType.RETURN) return TransactionStatus.APPROVED;
    return TransactionStatus.PENDING;
  };

  if (supabase) {
    try {
      if (transactions.length === 0) return { success: true };

      // 1. Pre-Validation (Stock Check)
      const saleTransactions = transactions.filter(t => t.type === TransactionType.SALE);
      if (saleTransactions.length > 0) {
          const partNumbers = [...new Set(saleTransactions.map(t => t.partNumber.toUpperCase()))];
          const { data: stocks } = await supabase
              .from('inventory')
              .select('part_number, quantity')
              .in('part_number', partNumbers);

          if (stocks) {
              const stockMap = new Map<string, number>();
              stocks.forEach((s: any) => stockMap.set(s.part_number.toUpperCase(), s.quantity));
              for (const tx of saleTransactions) {
                  const currentStock = stockMap.get(tx.partNumber.toUpperCase()) || 0;
                  if (tx.quantity > currentStock) {
                      return { success: false, message: `Insufficient stock for '${tx.partNumber}'. Available: ${currentStock}` };
                  }
              }
          }
      }

      // 2. Insert Transactions (Force Uppercase PN)
      const dbRows = transactions.map(t => ({
        part_number: t.partNumber.toUpperCase(),
        type: t.type,
        quantity: t.quantity,
        price: t.price,
        paid_amount: t.paidAmount || 0,
        customer_name: t.customerName,
        status: getInitialStatus(t.type),
        payment_status: t.paymentStatus || 'PAID',
        created_by_role: t.createdByRole,
        related_transaction_id: t.relatedTransactionId
      }));

      const { error: insertError } = await supabase.from('transactions').insert(dbRows);
      if (insertError) throw new Error(insertError.message);

      // 3. Update Inventory immediately for APPROVED movements
      for (const tx of transactions) {
        const status = getInitialStatus(tx.type);
        if (status === TransactionStatus.APPROVED && tx.type !== TransactionType.PURCHASE_ORDER) {
           await updateStockForTransaction(tx.partNumber.toUpperCase(), tx.type, tx.quantity);
        }
      }
      return { success: true };
    } catch (error: any) {
      console.error("Supabase Transaction Error:", error);
      return { success: false, message: error.message };
    }
  }

  // --- OFFLINE FALLBACK (LOCAL STORAGE) ---
  const localTransactions: Transaction[] = JSON.parse(localStorage.getItem(TX_STORAGE_KEY) || '[]');
  const localInventory: StockItem[] = JSON.parse(localStorage.getItem(INV_STORAGE_KEY) || '[]');

  for (const t of transactions) {
    const status = getInitialStatus(t.type);
    const upperPN = t.partNumber.toUpperCase();
    const newTx: Transaction = {
      ...t,
      partNumber: upperPN,
      id: Math.random().toString(36).substring(7),
      status,
      createdAt: new Date().toISOString()
    };
    localTransactions.push(newTx);

    if (status === TransactionStatus.APPROVED) {
      const invIdx = localInventory.findIndex(i => i.partNumber.toUpperCase() === upperPN);
      if (invIdx > -1) {
        if (t.type === TransactionType.SALE) localInventory[invIdx].quantity -= t.quantity;
        else if (t.type === TransactionType.PURCHASE || t.type === TransactionType.RETURN) localInventory[invIdx].quantity += t.quantity;
        localInventory[invIdx].lastUpdated = new Date().toISOString();
        if (localInventory[invIdx].quantity < 0) localInventory[invIdx].quantity = 0;
      }
    }
  }

  localStorage.setItem(TX_STORAGE_KEY, JSON.stringify(localTransactions));
  localStorage.setItem(INV_STORAGE_KEY, JSON.stringify(localInventory));
  return { success: true };
};

const updateStockForTransaction = async (partNumber: string, type: TransactionType, quantity: number) => {
  if (!supabase) return;

  const upperPN = partNumber.toUpperCase();

  // 1. Fetch current exact quantity from DB using ilike for safety
  const { data: items, error: fetchError } = await supabase
    .from('inventory')
    .select('quantity, part_number, is_archived')
    .ilike('part_number', upperPN)
    .limit(1);

  if (fetchError || !items || items.length === 0) {
    console.error(`UpdateStock: Item ${upperPN} not found in inventory.`);
    return;
  }

  const dbItem = items[0];
  let newQty = dbItem.quantity;

  if (type === TransactionType.SALE) newQty = dbItem.quantity - quantity;
  else if (type === TransactionType.PURCHASE || type === TransactionType.RETURN) newQty = dbItem.quantity + quantity;

  if (newQty < 0) newQty = 0;

  const updatePayload: any = { 
    quantity: newQty, 
    last_updated: new Date().toISOString() 
  };

  // Auto-unarchive if stock is added
  if (dbItem.is_archived && newQty > 0) {
    updatePayload.is_archived = false;
  }

  // 2. Perform the Update. Use the EXACT part_number returned from DB to ensure .eq() matches
  const { error: updateError } = await supabase
    .from('inventory')
    .update(updatePayload)
    .eq('part_number', dbItem.part_number);

  if (updateError) {
    console.error(`UpdateStock: Failed to update ${dbItem.part_number}:`, updateError.message);
  }
};

export const fetchTransactions = async (
  status?: TransactionStatus | TransactionStatus[], 
  type?: TransactionType | TransactionType[]
): Promise<Transaction[]> => {
  if (supabase) {
    let query = supabase.from('transactions').select('*').order('created_at', { ascending: false });
    if (status) {
      if (Array.isArray(status)) query = query.in('status', status);
      else query = query.eq('status', status);
    }
    if (type) {
      if (Array.isArray(type)) query = query.in('type', type);
      else query = query.eq('type', type);
    }
    const { data, error } = await query;
    if (error) return [];
    return data.map(mapDBToTransaction);
  }

  const local: Transaction[] = JSON.parse(localStorage.getItem(TX_STORAGE_KEY) || '[]');
  return local.reverse();
};

export const fetchItemTransactions = async (partNumber: string): Promise<Transaction[]> => {
  if (!supabase) return [];
  const { data, error } = await supabase
    .from('transactions')
    .select('*')
    .ilike('part_number', partNumber)
    .order('created_at', { ascending: false });
  if (error || !data) return [];
  return data.map(mapDBToTransaction);
};

export const approveTransaction = async (id: string, partNumber: string, type: TransactionType, quantity: number): Promise<void> => {
  if (!supabase) return;
  const { error: txError } = await supabase.from('transactions').update({ status: TransactionStatus.APPROVED }).eq('id', id);
  if (txError) throw new Error(txError.message);
  if (type !== TransactionType.PURCHASE_ORDER) {
    await updateStockForTransaction(partNumber, type, quantity);
  }
};

export const rejectTransaction = async (id: string): Promise<void> => {
  if (!supabase) return;
  await supabase.from('transactions').update({ status: TransactionStatus.REJECTED }).eq('id', id);
};

export const updateBillPayment = async (createdAt: string, customerName: string, additionalAmount: number): Promise<{ success: boolean; message?: string }> => {
  if (!supabase) return { success: false, message: "Database not connected" };
  try {
    const { data: items } = await supabase.from('transactions').select('*').eq('created_at', createdAt).eq('customer_name', customerName).eq('type', 'SALE');
    if (!items || items.length === 0) throw new Error("Bill not found.");
    const totalBillAmount = items.reduce((sum, i) => sum + (i.price * i.quantity), 0);
    const currentPaidAmount = items.reduce((sum, i) => sum + i.paid_amount, 0);
    const newTotalPaid = Math.min(totalBillAmount, currentPaidAmount + additionalAmount);
    const finalPaymentStatus = newTotalPaid >= totalBillAmount ? 'PAID' : 'PENDING';
    for (const item of items) {
       const itemTotal = item.price * item.quantity;
       const proportion = totalBillAmount > 0 ? itemTotal / totalBillAmount : 0;
       const newItemPaid = newTotalPaid * proportion;
       await supabase.from('transactions').update({ paid_amount: newItemPaid, payment_status: finalPaymentStatus }).eq('id', item.id);
    }
    return { success: true };
  } catch (err: any) {
    return { success: false, message: err.message };
  }
};

export interface SoldItemStats { partNumber: string; name: string; quantitySold: number; totalRevenue: number; }
export interface AnalyticsData { totalSales: number; totalReturns: number; totalPurchases: number; netRevenue: number; salesCount: number; returnCount: number; soldItems: SoldItemStats[]; }

export const fetchAnalytics = async (startDate: Date, endDate: Date): Promise<AnalyticsData> => {
  const allTxs = await fetchTransactions(TransactionStatus.APPROVED);
  const filtered = allTxs.filter(t => {
     const d = new Date(t.createdAt);
     return d >= startDate && d <= endDate;
  });
  let totalSales = 0, totalReturns = 0, totalPurchases = 0, salesCount = 0, returnCount = 0;
  const soldItemsMap = new Map<string, { qty: number, rev: number }>();
  filtered.forEach(t => {
    const val = (t.price || 0) * (t.quantity || 0);
    const pnKey = t.partNumber.toUpperCase();
    if (t.type === TransactionType.SALE) {
      totalSales += val; salesCount++;
      const current = soldItemsMap.get(pnKey) || { qty: 0, rev: 0 };
      soldItemsMap.set(pnKey, { qty: current.qty + t.quantity, rev: current.rev + val });
    } else if (t.type === TransactionType.RETURN) {
      totalReturns += val; returnCount++;
    } else if (t.type === TransactionType.PURCHASE) {
      totalPurchases += val;
    }
  });
  const soldItems: SoldItemStats[] = [];
  soldItemsMap.forEach((val, key) => { soldItems.push({ partNumber: key, name: '', quantitySold: val.qty, totalRevenue: val.rev }); });
  return { totalSales, totalReturns, totalPurchases, netRevenue: totalSales - totalReturns, salesCount, returnCount, soldItems };
};

export const fetchUninvoicedSales = async (): Promise<Transaction[]> => {
  if (!supabase) return [];
  const { data } = await supabase.from('transactions').select('*').eq('type', 'SALE').eq('status', 'APPROVED').is('invoice_id', null).order('created_at', { ascending: false });
  if (!data) return [];
  return data.map(mapDBToTransaction);
};

export const fetchInvoices = async (): Promise<Invoice[]> => {
  if (!supabase) return [];
  const { data } = await supabase.from('invoices').select('*').order('date', { ascending: false });
  if (!data) return [];
  return data.map((i: any) => ({
      id: i.id, invoiceNumber: i.invoice_number, date: i.date, customerName: i.customer_name,
      customerPhone: i.customer_phone, customerAddress: i.customer_address, customerGst: i.customer_gst,
      totalAmount: i.total_amount, paidAmount: i.paid_amount, taxAmount: i.tax_amount,
      paymentMode: i.payment_mode, itemsCount: i.items_count, generatedBy: i.generated_by
  }));
};

export const generateTaxInvoiceRecord = async (
  transactionIds: string[], 
  customerDetails: { name: string, phone: string, address: string, gst: string, paymentMode: string, paidAmount?: number },
  totals: { amount: number, tax: number },
  userRole: string
): Promise<{ success: boolean, invoice?: Invoice, message?: string }> => {
  if (!supabase) return { success: false, message: "Database not connected" };
  const invoiceNumber = `INV-${Date.now().toString().slice(-8)}`;
  try {
    const { data: invoiceData, error: invError } = await supabase.from('invoices').insert({
        invoice_number: invoiceNumber, customer_name: customerDetails.name, customer_phone: customerDetails.phone,
        customer_address: customerDetails.address, customer_gst: customerDetails.gst, total_amount: totals.amount,
        paid_amount: customerDetails.paidAmount || 0, tax_amount: totals.tax, payment_mode: customerDetails.paymentMode.toUpperCase(), 
        items_count: transactionIds.length, generated_by: userRole
      }).select().single();
    if (invError || !invoiceData) throw new Error(invError?.message || "Failed to create invoice");
    const { error: txError } = await supabase.from('transactions').update({ invoice_id: invoiceData.id }).in('id', transactionIds);
    if (txError) throw new Error("Failed to link items to invoice");
    return { success: true, invoice: {
        id: invoiceData.id, invoiceNumber: invoiceData.invoice_number, date: invoiceData.date, customerName: invoiceData.customer_name,
        customerPhone: invoiceData.customer_phone, customerAddress: invoiceData.customer_address, customerGst: invoiceData.customer_gst,
        totalAmount: invoiceData.total_amount, paidAmount: invoiceData.paid_amount, taxAmount: invoiceData.tax_amount,
        paymentMode: invoiceData.payment_mode as any, itemsCount: invoiceData.items_count, generatedBy: invoiceData.generated_by
      } };
  } catch (err: any) { return { success: false, message: err.message }; }
};

import { INITIAL_STOCK_DATA } from '../constants';
import { Brand, PriceHistoryEntry, StockItem, StockStats, UploadHistoryEntry } from '../types';
import { supabase } from './supabase';

const STORAGE_KEY = 'sparezy_inventory_v1';

// --- Types for Supabase DB Row (snake_case) ---
interface DBItem {
  id?: string;
  part_number: string;
  name: string;
  brand: string;
  hsn_code: string;
  quantity: number;
  min_stock_threshold: number;
  price: number;
  last_updated: string;
  is_archived: boolean;
}

// --- Mappers ---
const toAppItem = (dbItem: DBItem): StockItem => ({
  id: dbItem.id || '',
  partNumber: dbItem.part_number.toUpperCase(),
  name: dbItem.name,
  brand: dbItem.brand as Brand,
  hsnCode: dbItem.hsn_code,
  quantity: dbItem.quantity,
  minStockThreshold: dbItem.min_stock_threshold,
  price: dbItem.price,
  lastUpdated: dbItem.last_updated,
  isArchived: dbItem.is_archived || false
});

const toDBItem = (item: Partial<StockItem>): Partial<DBItem> => {
  const dbItem: Partial<DBItem> = {};
  if (item.partNumber) dbItem.part_number = item.partNumber.toUpperCase();
  if (item.name) dbItem.name = item.name;
  if (item.brand) dbItem.brand = item.brand;
  if (item.hsnCode) dbItem.hsn_code = item.hsnCode;
  if (item.quantity !== undefined) dbItem.quantity = item.quantity;
  if (item.minStockThreshold !== undefined) dbItem.min_stock_threshold = item.minStockThreshold;
  if (item.price !== undefined) dbItem.price = item.price;
  if (item.lastUpdated) dbItem.last_updated = item.lastUpdated;
  if (item.isArchived !== undefined) dbItem.is_archived = item.isArchived;
  return dbItem;
};

// Helper to simulate network delay for local testing
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const getFromLS = (): StockItem[] => {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (!stored) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_STOCK_DATA));
    return INITIAL_STOCK_DATA;
  }
  return JSON.parse(stored);
};

export const fetchInventory = async (): Promise<StockItem[]> => {
  if (supabase) {
    let allData: DBItem[] = [];
    let page = 0;
    const PAGE_SIZE = 1000;
    let hasMore = true;

    while (hasMore) {
      const { data, error } = await supabase
        .from('inventory')
        .select('*')
        .range(page * PAGE_SIZE, (page + 1) * PAGE_SIZE - 1)
        .order('part_number', { ascending: true });

      if (error) {
        console.error('Supabase fetch error:', error);
        break;
      }

      if (data && data.length > 0) {
        allData = allData.concat(data as DBItem[]);
        if (data.length < PAGE_SIZE) hasMore = false;
        page++;
      } else {
        hasMore = false;
      }
    }
    return allData.map(toAppItem);
  }

  await delay(300); 
  return getFromLS();
};

export const fetchItemDetails = async (partNumber: string): Promise<StockItem | null> => {
  const upperPN = partNumber.toUpperCase();
  if (supabase) {
    const { data, error } = await supabase
      .from('inventory')
      .select('*')
      .ilike('part_number', upperPN)
      .single();

    if (error || !data) return null;
    return toAppItem(data);
  }
  const items = getFromLS();
  return items.find(i => i.partNumber.toUpperCase() === upperPN) || null;
};

export const toggleArchiveStatus = async (partNumber: string, isArchived: boolean): Promise<void> => {
  if (!supabase) return;
  const upperPN = partNumber.toUpperCase();
  const { error } = await supabase
    .from('inventory')
    .update({ is_archived: isArchived })
    .ilike('part_number', upperPN);

  if (error) throw new Error(error.message);
};

export const saveInventory = async (items: StockItem[]): Promise<void> => {
  if (supabase) return;
  await delay(300);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
};

export const bulkArchiveItems = async (partNumbers: string[], isArchived: boolean): Promise<void> => {
  if (supabase) {
    const upperPNs = partNumbers.map(p => p.toUpperCase());
    const BATCH_SIZE = 200;
    for (let i = 0; i < upperPNs.length; i += BATCH_SIZE) {
      const batch = upperPNs.slice(i, i + BATCH_SIZE);
      const { error } = await supabase
        .from('inventory')
        .update({ is_archived: isArchived })
        .in('part_number', batch);
      if (error) throw new Error(error.message);
    }
    return;
  }

  await delay(500);
  const items = getFromLS();
  const idsToUpdate = new Set(partNumbers.map(p => p.toUpperCase()));
  const updatedItems = items.map(item => {
    if (idsToUpdate.has(item.partNumber.toUpperCase())) return { ...item, isArchived };
    return item;
  });
  await saveInventory(updatedItems);
};

export const getStats = (items: StockItem[]): StockStats => {
  const activeItems = items.filter(i => !i.isArchived);
  return {
    totalItems: activeItems.reduce((acc, item) => acc + item.quantity, 0),
    totalValue: activeItems.reduce((acc, item) => acc + (item.quantity * (item.price || 0)), 0),
    lowStockCount: activeItems.filter(i => i.quantity > 0 && i.quantity < i.minStockThreshold).length,
    zeroStockCount: activeItems.filter(i => i.quantity === 0).length,
  };
};

export interface UpdateResult {
  added: number;
  updated: number;
  priceUpdates: number;
  stockUpdates: number;
  errors: string[];
}

export const updateOrAddItems = async (
  newItems: Partial<StockItem>[], 
  metadata?: { fileName: string, mode: string }
): Promise<UpdateResult> => {
  const result: UpdateResult = { added: 0, updated: 0, priceUpdates: 0, stockUpdates: 0, errors: [] };

  if (supabase) {
    const partNumbers = newItems.map(i => i.partNumber?.toUpperCase()).filter(Boolean) as string[];
    if (partNumbers.length === 0) {
      result.errors.push("No valid part numbers found.");
      return result;
    }

    let existingItemsMap = new Map<string, StockItem>();
    const FETCH_BATCH_SIZE = 200;
    for (let i = 0; i < partNumbers.length; i += FETCH_BATCH_SIZE) {
      const batch = partNumbers.slice(i, i + FETCH_BATCH_SIZE);
      const { data, error } = await supabase.from('inventory').select('*').in('part_number', batch);
      if (!error && data) {
        data.forEach((d: any) => {
          const item = toAppItem(d);
          existingItemsMap.set(item.partNumber.toUpperCase(), item);
        });
      }
    }

    if (metadata) {
      const snapshot = newItems.map(newItem => {
        if (!newItem.partNumber) return null;
        const key = newItem.partNumber.toUpperCase();
        const existing = existingItemsMap.get(key);
        return { part_number: key, previous_state: existing ? toDBItem(existing) : null };
      }).filter(Boolean);
      await supabase.from('upload_history').insert({
        file_name: metadata.fileName, upload_mode: metadata.mode, item_count: snapshot.length,
        status: 'SUCCESS', snapshot_data: snapshot, created_at: new Date().toISOString()
      });
    }

    const upsertPayload: Partial<DBItem>[] = [];
    const priceHistoryPayload: any[] = [];

    newItems.forEach((newItem, index) => {
      if (!newItem.partNumber) {
        result.errors.push(`Row ${index + 1}: Missing Part Number`);
        return;
      }

      const upperPN = newItem.partNumber.toUpperCase();
      const existingItem = existingItemsMap.get(upperPN);

      if (existingItem) {
        let itemChanged = false;
        if (newItem.quantity !== undefined && newItem.quantity !== existingItem.quantity) {
          result.stockUpdates++;
          itemChanged = true;
        }
        if (newItem.price !== undefined && newItem.price !== existingItem.price) {
          result.priceUpdates++;
          itemChanged = true;
          priceHistoryPayload.push({ part_number: upperPN, old_price: existingItem.price, new_price: newItem.price, change_date: new Date().toISOString() });
        }
        if (itemChanged) result.updated++;

        const finalQuantity = newItem.quantity !== undefined ? newItem.quantity : existingItem.quantity;
        const shouldUnarchive = existingItem.isArchived && finalQuantity > 0;

        upsertPayload.push({
          part_number: upperPN, 
          name: newItem.name !== undefined ? newItem.name : existingItem.name,
          brand: newItem.brand !== undefined ? newItem.brand : existingItem.brand,
          hsn_code: newItem.hsnCode !== undefined ? newItem.hsnCode : existingItem.hsnCode,
          quantity: finalQuantity,
          min_stock_threshold: newItem.minStockThreshold !== undefined ? newItem.minStockThreshold : existingItem.minStockThreshold,
          price: newItem.price !== undefined ? newItem.price : existingItem.price,
          last_updated: new Date().toISOString(),
          is_archived: shouldUnarchive ? false : existingItem.isArchived
        });
      } else {
        result.added++;
        let detectedBrand = Brand.UNKNOWN;
        if (upperPN.startsWith('HY')) detectedBrand = Brand.HYUNDAI;
        else if (upperPN.startsWith('MH')) detectedBrand = Brand.MAHINDRA;

        upsertPayload.push({
          part_number: upperPN, name: newItem.name || 'AI Added Part', brand: (newItem.brand || detectedBrand) as string,
          hsn_code: newItem.hsnCode || 'N/A', quantity: newItem.quantity !== undefined ? newItem.quantity : 0,
          min_stock_threshold: newItem.minStockThreshold !== undefined ? newItem.minStockThreshold : 3,
          price: newItem.price !== undefined ? newItem.price : 0, last_updated: new Date().toISOString(), is_archived: false
        });
      }
    });

    const UPLOAD_BATCH_SIZE = 500;
    for (let i = 0; i < upsertPayload.length; i += UPLOAD_BATCH_SIZE) {
      const batch = upsertPayload.slice(i, i + UPLOAD_BATCH_SIZE);
      await supabase.from('inventory').upsert(batch, { onConflict: 'part_number' });
    }

    if (priceHistoryPayload.length > 0) await supabase.from('price_history').insert(priceHistoryPayload);
    return result;
  }

  const currentInventory = getFromLS();
  newItems.forEach((newItem) => {
    if (!newItem.partNumber) return;
    const upperPN = newItem.partNumber.toUpperCase();
    const existingIndex = currentInventory.findIndex(i => i.partNumber.toUpperCase() === upperPN);

    if (existingIndex > -1) {
        const existingItem = currentInventory[existingIndex];
        const finalQuantity = newItem.quantity !== undefined ? newItem.quantity : existingItem.quantity;
        const shouldUnarchive = existingItem.isArchived && finalQuantity > 0;
        currentInventory[existingIndex] = {
            ...existingItem, ...newItem, partNumber: upperPN, quantity: finalQuantity,
            lastUpdated: new Date().toISOString(), isArchived: shouldUnarchive ? false : existingItem.isArchived
        };
        result.updated++;
    } else {
        currentInventory.push({
            id: crypto.randomUUID(), partNumber: upperPN, name: newItem.name || 'Unknown Part',
            brand: newItem.brand as Brand, hsnCode: newItem.hsnCode || 'N/A', quantity: newItem.quantity || 0,
            minStockThreshold: newItem.minStockThreshold || 3, price: newItem.price || 0,
            lastUpdated: new Date().toISOString(), isArchived: false
        });
        result.added++;
    }
  });

  await saveInventory(currentInventory);
  return result;
};

export const fetchUploadHistory = async (): Promise<UploadHistoryEntry[]> => {
